  5→// Helper to get Monday of a given week
  6→function getMondayOfWeek(date: Date): Date {
  7→  const d = new Date(date);
  8→  const day = d.getDay();
  9→  const diff = d.getDate() - day + (day === 0 ? -6 : 1); // Adjust for Sunday
 10→  return new Date(d.setDate(diff));
 11→}
 12→
 13→// Helper to calculate weekly breakdown for the month
 14→interface WeekDataInternal {
 15→  weekNumber: number;
 16→  startDate: Date;
 17→  endDate: Date;
 18→  total: number;
 19→  count: number;
 20→  categories: Record<string, { name: string; color: string; total: number }>;
 21→}
 22→
 23→function calculateWeeklyBreakdown(
 24→  transactions: Array<{
 25→    date: Date;
 26→    amount: number;
 27→    type: string;
 28→    categoryId: string | null;
 29→    category: { name: string; color: string } | null;
 30→  }>,
 31→  monthStart: Date,
 32→  monthEnd: Date
 33→) {
 34→  // Get all weeks that overlap with this month
 35→  const weeks: WeekDataInternal[] = [];
 36→  let weekNumber = 1;
 37→  let currentDate = new Date(monthStart);
 38→
 39→  while (currentDate <= monthEnd) {
 40→    // Find the start of the week (Sunday or first day of month)
 41→    const weekStart = new Date(currentDate);
 42→    if (weekStart < monthStart) {
 43→      weekStart.setTime(monthStart.getTime());
 44→    }
 45→    weekStart.setHours(0, 0, 0, 0);
 46→
 47→    // Find the end of the week (Saturday or last day of month)
 48→    const weekEnd = new Date(currentDate);
 49→    // Move to Saturday (day 6)
 50→    const daysUntilSaturday = 6 - weekEnd.getDay();
 51→    weekEnd.setDate(weekEnd.getDate() + daysUntilSaturday);
 52→    weekEnd.setHours(23, 59, 59, 999);
 53→
 54→    // Cap at month end
 55→    if (weekEnd > monthEnd) {
 56→      weekEnd.setTime(monthEnd.getTime());
 57→      weekEnd.setHours(23, 59, 59, 999);
 58→    }
 59→
 60→    weeks.push({
 61→      weekNumber,
 62→      startDate: new Date(weekStart),
 63→      endDate: new Date(weekEnd),
 64→      total: 0,
 65→      count: 0,
 66→      categories: {},
 67→    });
 68→
 69→    // Move to next week (Sunday)
 70→    currentDate = new Date(weekEnd);
 71→    currentDate.setDate(currentDate.getDate() + 1);
 72→    currentDate.setHours(0, 0, 0, 0);
 73→    weekNumber++;
 74→  }
 75→
 76→  // Distribute transactions into weeks
 77→  for (const t of transactions) {
 78→    if (t.type !== "EXPENSE") continue;
 79→
 80→    const tDate = new Date(t.date);
 81→    tDate.setHours(12, 0, 0, 0); // Normalize to midday to avoid timezone issues
 82→
 83→    for (const week of weeks) {
 84→      if (tDate >= week.startDate && tDate <= week.endDate) {
 85→        week.total += Math.abs(t.amount);
 86→        week.count++;
 87→
 88→        if (t.categoryId && t.category) {
 89→          if (!week.categories[t.categoryId]) {
 90→            week.categories[t.categoryId] = {
 91→              name: t.category.name,
 92→              color: t.category.color,
 93→              total: 0,
 94→            };
 95→          }
 96→          week.categories[t.categoryId].total += Math.abs(t.amount);
 97→        }
 98→        break;
 99→      }
100→    }
101→  }
102→
103→  // Format weeks for response
104→  const formattedWeeks = weeks.map((week) => {
105→    const daysDiff =
106→      Math.ceil(
107→        (week.endDate.getTime() - week.startDate.getTime()) / (1000 * 60 * 60 * 24)
108→      ) + 1;
109→
110→    return {
111→      weekNumber: week.weekNumber,
112→      startDate: week.startDate.toISOString(),
113→      endDate: week.endDate.toISOString(),
114→      total: week.total,
115→      count: week.count,
116→      dailyAverage: daysDiff > 0 ? week.total / daysDiff : 0,
117→      categories: Object.entries(week.categories)
118→        .map(([categoryId, data]) => ({
119→          categoryId,
120→          categoryName: data.name,
121→          categoryColor: data.color,
122→          total: data.total,
123→        }))
124→        .sort((a, b) => b.total - a.total),
125→    };
126→  });
127→
128→  // Find highest and lowest spending weeks
129→  const weeksWithSpending = formattedWeeks.filter((w) => w.total > 0);
130→  let highestWeek = 1;
131→  let lowestWeek = 1;
132→  let maxTotal = 0;
133→  let minTotal = Infinity;
134→
135→  for (const week of weeksWithSpending) {
136→    if (week.total > maxTotal) {
137→      maxTotal = week.total;
138→      highestWeek = week.weekNumber;
139→    }
140→    if (week.total < minTotal) {
141→      minTotal = week.total;
142→      lowestWeek = week.weekNumber;
143→    }
144→  }
145→
146→  const totalSpending = formattedWeeks.reduce((sum, w) => sum + w.total, 0);
147→  const averagePerWeek = formattedWeeks.length > 0 ? totalSpending / formattedWeeks.length : 0;
148→
149→  return {
150→    weeks: formattedWeeks,
151→    highestWeek,
152→    lowestWeek,
153→    averagePerWeek,
154→  };
155→}
