157→// Helper to calculate expense adjustment for partial bill payments
158→// When a bill was partially paid, we need to adjust the expense total
159→// to reflect what was actually paid (amountPaid), not the full bill amount (totalBillAmount)
160→interface BillPaymentRecord {
161→  billMonth: number;
162→  billYear: number;
163→  origin: string;
164→  totalBillAmount: number;
165→  amountPaid: number;
166→  amountCarried: number;
167→}
168→
169→function calculatePartialPaymentAdjustment(
170→  billPayments: BillPaymentRecord[],
171→  month: number,
172→  year: number
173→): number {
174→  // Find all bill payments for this specific month/year
175→  const monthPayments = billPayments.filter(
176→    (bp) => bp.billMonth === month && bp.billYear === year
177→  );
178→
179→  // The adjustment is the difference between what was consumed (totalBillAmount)
180→  // and what was actually paid (amountPaid)
181→  // A positive adjustment means we need to REDUCE the expenses shown
182→  // (because we're showing less than what was consumed)
183→  let adjustment = 0;
184→  for (const payment of monthPayments) {
185→    // adjustment = totalBillAmount - amountPaid
186→    // This is the amount that was carried/financed, not paid this month
187→    adjustment += payment.amountCarried;
188→  }
189→
190→  return adjustment;
191→}
