193→export async function GET(request: NextRequest) {
194→  try {
195→    const userId = await getAuthenticatedUserId();
196→    const searchParams = request.nextUrl.searchParams;
197→    const month = searchParams.get("month");
198→    const year = searchParams.get("year");
199→
200→    const currentDate = new Date();
201→    const targetMonth = month ? parseInt(month) : currentDate.getMonth() + 1;
202→    const targetYear = year ? parseInt(year) : currentDate.getFullYear();
203→
204→    const startDate = new Date(targetYear, targetMonth - 1, 1);
205→    const endDate = new Date(targetYear, targetMonth, 0);
206→    endDate.setHours(23, 59, 59, 999);
207→
208→    // Check if viewing a past month (for auto-recording savings history)
209→    const isCurrentMonth = targetMonth === currentDate.getMonth() + 1 && targetYear === currentDate.getFullYear();
210→    const isPastMonth = new Date(targetYear, targetMonth - 1, 1) < new Date(currentDate.getFullYear(), currentDate.getMonth(), 1);
211→
212→    // Calculate date ranges for consolidated query
213→    const sixMonthsAgo = new Date(targetYear, targetMonth - 6, 1);
214→    const futureDate = new Date(targetYear, targetMonth + 3, 0); // For installments (next 3 months)
215→    futureDate.setHours(23, 59, 59, 999);
216→
217→    // Previous month boundaries
218→    const prevMonthStart = new Date(targetYear, targetMonth - 2, 1);
219→    const prevMonthEnd = new Date(targetYear, targetMonth - 1, 0);
220→    prevMonthEnd.setHours(23, 59, 59, 999);
221→
222→    // Weekly boundaries for current month
223→    const today = new Date();
224→    const currentWeekStart = getMondayOfWeek(today);
225→    currentWeekStart.setHours(0, 0, 0, 0);
226→    const prevWeekStart = new Date(currentWeekStart);
227→    prevWeekStart.setDate(prevWeekStart.getDate() - 7);
228→    const prevWeekEnd = new Date(currentWeekStart);
229→    prevWeekEnd.setDate(prevWeekEnd.getDate() - 1);
230→    prevWeekEnd.setHours(23, 59, 59, 999);
231→
232→    // ===========================================
233→    // OPTIMIZED: Run all queries in parallel
234→    // ===========================================
235→    const [
236→      // Query 1: All transactions for 6 months (includes current, previous, and monthly data)
237→      allTransactions,
238→      // Query 2: Active budgets
239→      budgets,
240→      // Query 3: Fixed expenses (distinct by description)
241→      fixedExpenses,
242→      // Query 4: Future installment transactions (for upcoming installments)
243→      futureInstallments,
244→      // Query 5: Standalone installments for projection
245→      standaloneInstallments,
246→      // Query 6: Savings goal setting
247→      savingsGoalSetting,
248→      // Query 7: Bill payments for 6 months (for partial payment adjustments)
249→      billPayments,
250→    ] = await Promise.all([
251→      // Query 1: All transactions for 6 months with category and installment info
252→      prisma.transaction.findMany({
253→        where: {
254→          userId,
255→          date: {
256→            gte: sixMonthsAgo,
257→            lte: endDate,
258→          },
259→          deletedAt: null,
260→        },
261→        include: {
262→          category: true,
263→          installment: true,
264→        },
265→      }),
266→
267→      // Query 2: Active budgets with category
268→      prisma.budget.findMany({
269→        where: { userId, isActive: true },
270→        include: { category: true },
271→      }),
272→
273→      // Query 3: Fixed expenses (distinct by description)
274→      prisma.transaction.findMany({
275→        where: {
276→          userId,
277→          isFixed: true,
278→          type: "EXPENSE",
279→          deletedAt: null,
280→        },
281→        include: {
282→          category: true,
283→        },
284→        distinct: ["description"],
285→      }),
286→
287→      // Query 4: Future grouped installments (next 3 months)
288→      prisma.transaction.findMany({
289→        where: {
290→          userId,
291→          isInstallment: true,
292→          installmentId: { not: null },
293→          date: {
294→            gt: endDate,
295→            lte: futureDate,
296→          },
297→          deletedAt: null,
298→        },
299→        include: {
300→          category: true,
301→          installment: true,
302→        },
303→        orderBy: {
304→          date: "asc",
305→        },
306→      }),
307→
308→      // Query 5: Standalone installments for projection
309→      prisma.transaction.findMany({
310→        where: {
311→          userId,
312→          isInstallment: true,
313→          installmentId: null,
314→          totalInstallments: { not: null },
315→          currentInstallment: { not: null },
316→          deletedAt: null,
317→        },
318→        include: {
319→          category: true,
320→        },
321→      }),
322→
323→      // Query 6: Savings goal setting
324→      prisma.settings.findUnique({
325→        where: { key_userId: { key: "savingsGoal", userId } },
326→      }),
327→
328→      // Query 7: Bill payments for 6 months (for partial payment adjustments)
329→      prisma.billPayment.findMany({
330→        where: {
331→          userId,
332→          billYear: {
333→            gte: sixMonthsAgo.getFullYear(),
334→            lte: targetYear,
335→          },
336→        },
337→      }),
338→    ]);
339→
340→    // ===========================================
341→    // DERIVE DATA FROM CONSOLIDATED QUERIES
342→    // ===========================================
343→
344→    // Filter transactions for current month
345→    const transactions = allTransactions.filter((t) => {
346→      const tDate = new Date(t.date);
347→      return tDate >= startDate && tDate <= endDate;
348→    });
349→
350→    // Filter transactions for previous month
351→    const prevTransactions = allTransactions.filter((t) => {
352→      const tDate = new Date(t.date);
353→      return tDate >= prevMonthStart && tDate <= prevMonthEnd;
354→    });
355→
356→    // Calculate previous month totals and category breakdown
357→    let prevIncome = 0;
358→    let prevExpenseRaw = 0;
359→    const prevCategoryTotals: Record<string, { total: number; name: string; color: string }> = {};
360→
361→    for (const t of prevTransactions) {
362→      if (t.type === "INCOME") {
363→        prevIncome += Math.abs(t.amount);
364→      } else if (t.type === "EXPENSE") {
365→        prevExpenseRaw += Math.abs(t.amount);
366→        // Track category totals for previous month
367→        if (t.category && t.categoryId) {
368→          if (!prevCategoryTotals[t.categoryId]) {
369→            prevCategoryTotals[t.categoryId] = {
370→              total: 0,
371→              name: t.category.name,
372→              color: t.category.color,
373→            };
374→          }
375→          prevCategoryTotals[t.categoryId].total += Math.abs(t.amount);
376→        }
377→      }
378→      // TRANSFER is ignored in totals
379→    }
380→
381→    // Apply partial payment adjustment for previous month
382→    // This reduces expenses by the amount that was carried/financed instead of paid
383→    const prevMonthNumber = prevMonthStart.getMonth() + 1;
384→    const prevMonthYear = prevMonthStart.getFullYear();
385→    const prevPartialPaymentAdjustment = calculatePartialPaymentAdjustment(
386→      billPayments,
387→      prevMonthNumber,
388→      prevMonthYear
389→    );
390→    const prevExpense = Math.max(0, prevExpenseRaw - prevPartialPaymentAdjustment);
391→
392→    // Calculate current month summary
393→    let income = 0;
394→    let expenseRaw = 0;
395→    const categoryTotals: Record<string, { total: number; name: string; color: string }> = {};
396→
397→    for (const t of transactions) {
398→      if (t.type === "INCOME") {
399→        income += Math.abs(t.amount);
400→      } else if (t.type === "EXPENSE") {
401→        expenseRaw += Math.abs(t.amount);
402→      }
403→      // TRANSFER is ignored in totals
404→
405→      if (t.category && t.type === "EXPENSE") {
406→        if (!categoryTotals[t.categoryId!]) {
407→          categoryTotals[t.categoryId!] = {
408→            total: 0,
409→            name: t.category.name,
410→            color: t.category.color,
411→          };
412→        }
413→        categoryTotals[t.categoryId!].total += Math.abs(t.amount);
414→      }
415→    }
416→
417→    // Apply partial payment adjustment for current month
418→    // When a bill was partially paid, we show only what was paid (amountPaid),
419→    // not what was consumed (totalBillAmount). The carried amount appears
420→    // in subsequent months via generated carryover/financing transactions.
421→    const partialPaymentAdjustment = calculatePartialPaymentAdjustment(
422→      billPayments,
423→      targetMonth,
424→      targetYear
425→    );
426→    const expense = Math.max(0, expenseRaw - partialPaymentAdjustment);
427→
428→    // Calculate comparison percentages
429→    const incomeChange = prevIncome > 0 ? ((income - prevIncome) / prevIncome) * 100 : 0;
430→    const expenseChange = prevExpense > 0 ? ((expense - prevExpense) / prevExpense) * 100 : 0;
431→    const prevBalance = prevIncome - prevExpense;
432→    const balance = income - expense;
433→    const balanceChange = prevBalance !== 0 ? ((balance - prevBalance) / Math.abs(prevBalance)) * 100 : 0;
434→
435→    // Get category breakdown with previous month comparison
436→    const categoryBreakdown = Object.entries(categoryTotals)
437→      .map(([categoryId, data]) => {
438→        const prevTotal = prevCategoryTotals[categoryId]?.total || null;
439→        const changePercentage = prevTotal && prevTotal > 0
440→          ? ((data.total - prevTotal) / prevTotal) * 100
441→          : null;
442→
443→        return {
444→          categoryId,
445→          categoryName: data.name,
446→          categoryColor: data.color,
447→          total: data.total,
448→          percentage: expense > 0 ? (data.total / expense) * 100 : 0,
449→          previousTotal: prevTotal,
450→          changePercentage,
451→        };
452→      })
453→      .sort((a, b) => b.total - a.total);
454→
455→    // ===========================================
456→    // DERIVE MONTHLY DATA FROM 6-MONTH QUERY
457→    // ===========================================
458→    const monthlyData = [];
459→    for (let i = 5; i >= 0; i--) {
460→      const monthStart = new Date(targetYear, targetMonth - 1 - i, 1);
461→      const monthEnd = new Date(targetYear, targetMonth - i, 0);
462→      monthEnd.setHours(23, 59, 59, 999);
463→
464→      // Filter from already-fetched transactions
465→      const monthTransactions = allTransactions.filter((t) => {
466→        const tDate = new Date(t.date);
467→        return tDate >= monthStart && tDate <= monthEnd;
468→      });
469→
470→      let monthIncome = 0;
471→      let monthExpenseRaw = 0;
472→
473→      for (const t of monthTransactions) {
474→        if (t.type === "INCOME") {
475→          monthIncome += Math.abs(t.amount);
476→        } else if (t.type === "EXPENSE") {
477→          monthExpenseRaw += Math.abs(t.amount);
478→        }
479→        // TRANSFER is ignored in totals
480→      }
481→
482→      // Apply partial payment adjustment for this month
483→      const monthNumber = monthStart.getMonth() + 1;
484→      const monthYear = monthStart.getFullYear();
485→      const monthPartialPaymentAdjustment = calculatePartialPaymentAdjustment(
486→        billPayments,
487→        monthNumber,
488→        monthYear
489→      );
490→      const monthExpense = Math.max(0, monthExpenseRaw - monthPartialPaymentAdjustment);
491→
492→      monthlyData.push({
493→        month: monthStart.toLocaleDateString("pt-BR", { month: "short" }),
494→        year: monthStart.getFullYear(),
495→        income: monthIncome,
496→        expense: monthExpense,
497→      });
498→    }
499→
500→    // ===========================================
501→    // WEEKLY SUMMARY (derived from existing data when possible)
502→    // ===========================================
503→    let weeklySummary = null;
504→    if (isCurrentMonth) {
505→      // End of current week (Sunday)
506→      const currentWeekEnd = new Date(currentWeekStart);
507→      currentWeekEnd.setDate(currentWeekEnd.getDate() + 6);
508→      currentWeekEnd.setHours(23, 59, 59, 999);
509→
510→      // Current week transactions (filter from already-fetched data)
511→      const currentWeekTransactions = transactions.filter((t) => {
512→        const tDate = new Date(t.date);
513→        return tDate >= currentWeekStart && tDate <= currentWeekEnd && t.type === "EXPENSE";
514→      });
515→
516→      const currentWeekTotal = currentWeekTransactions.reduce((sum, t) => sum + Math.abs(t.amount), 0);
517→
518→      // Previous week transactions (filter from 6-month data if available)
519→      const prevWeekTransactions = allTransactions.filter((t) => {
520→        const tDate = new Date(t.date);
521→        return tDate >= prevWeekStart && tDate <= prevWeekEnd && t.type === "EXPENSE";
522→      });
523→
524→      const prevWeekTotal = prevWeekTransactions.reduce((sum, t) => sum + Math.abs(t.amount), 0);
525→
526→      const weekChangePercentage = prevWeekTotal > 0
527→        ? ((currentWeekTotal - prevWeekTotal) / prevWeekTotal) * 100
528→        : null;
529→
530→      weeklySummary = {
531→        currentWeek: {
532→          total: currentWeekTotal,
533→          count: currentWeekTransactions.length,
534→          startDate: currentWeekStart.toISOString(),
535→          endDate: currentWeekEnd.toISOString(),
536→        },
537→        previousWeek: {
538→          total: prevWeekTotal,
539→          count: prevWeekTransactions.length,
540→        },
541→        changePercentage: weekChangePercentage,
542→      };
543→    }
544→
545→    // Weekly Breakdown: gastos por semana do mês
546→    const weeklyBreakdown = calculateWeeklyBreakdown(transactions, startDate, endDate);
547→
548→    // ===========================================
549→    // SAVINGS GOAL
550→    // ===========================================
551→    const savingsGoal = savingsGoalSetting ? parseFloat(savingsGoalSetting.value) : null;
552→    const currentSavings = income - expense;
553→    const savingsPercentage = savingsGoal && savingsGoal > 0
554→      ? (currentSavings / savingsGoal) * 100
555→      : null;
556→
557→    // Feature 15: Auto-record savings history for past months
558→    if (isPastMonth && savingsGoal && savingsGoal > 0) {
559→      try {
560→        await prisma.savingsHistory.upsert({
561→          where: {
562→            month_year_userId: {
563→              month: targetMonth,
564→              year: targetYear,
565→              userId,
566→            },
567→          },
568→          update: {
569→            goal: savingsGoal,
570→            actual: currentSavings,
571→            isAchieved: currentSavings >= savingsGoal,
572→            percentage: (currentSavings / savingsGoal) * 100,
573→          },
574→          create: {
575→            userId,
576→            month: targetMonth,
577→            year: targetYear,
578→            goal: savingsGoal,
579→            actual: currentSavings,
580→            isAchieved: currentSavings >= savingsGoal,
581→            percentage: (currentSavings / savingsGoal) * 100,
582→          },
583→        });
584→      } catch (e) {
585→        // Silently ignore errors - this is a best-effort feature
586→        console.error("Error auto-recording savings history:", e);
587→      }
588→    }
589→
590→    // ===========================================
591→    // BUDGET ALERTS (using already-fetched budgets)
592→    // ===========================================
593→    const allBudgets = budgets
594→      .map((budget) => {
595→        const spent = categoryTotals[budget.categoryId]?.total || 0;
596→        const percentage = budget.amount > 0 ? (spent / budget.amount) * 100 : 0;
597→        return {
598→          categoryId: budget.categoryId,
599→          categoryName: budget.category.name,
600→          categoryColor: budget.category.color,
601→          budgetAmount: budget.amount,
602→          spent,
603→          percentage,
604→          isOver: spent > budget.amount,
605→        };
606→      })
607→      .sort((a, b) => b.percentage - a.percentage);
608→
609→    const budgetAlerts = allBudgets.filter((budget) => budget.percentage >= 80);
610→
611→    // ===========================================
612→    // UPCOMING INSTALLMENTS (project from standalone)
613→    // ===========================================
614→    const projectedInstallments: typeof futureInstallments = [];
615→    for (const t of standaloneInstallments) {
616→      if (!t.currentInstallment || !t.totalInstallments) continue;
617→
618→      const remainingInstallments = t.totalInstallments - t.currentInstallment;
619→      const transactionDate = new Date(t.date);
620→
621→      for (let i = 1; i <= remainingInstallments; i++) {
622→        const futureInstallmentDate = new Date(transactionDate);
623→        futureInstallmentDate.setMonth(transactionDate.getMonth() + i);
624→
625→        // Only include if within the date range (after current month, before futureDate)
626→        if (futureInstallmentDate > endDate && futureInstallmentDate <= futureDate) {
627→          projectedInstallments.push({
628→            ...t,
629→            id: `${t.id}-projected-${i}`,
630→            date: futureInstallmentDate,
631→            description: `${t.description} (${t.currentInstallment + i}/${t.totalInstallments})`,
632→            currentInstallment: t.currentInstallment + i,
633→            installment: null,
634→          });
635→        }
636→      }
637→    }
638→
639→    // Combine and sort all upcoming installments
640→    const upcomingInstallments = [...futureInstallments, ...projectedInstallments]
641→      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
642→
643→    return NextResponse.json({
644→      summary: {
645→        income,
646→        expense,
647→        balance,
648→      },
649→      comparison: {
650→        incomeChange,
651→        expenseChange,
652→        balanceChange,
653→        previousMonth: {
654→          income: prevIncome,
655→          expense: prevExpense,
656→          balance: prevBalance,
657→        },
658→      },
659→      savingsGoal: savingsGoal
660→        ? {
661→            goal: savingsGoal,
662→            current: currentSavings,
663→            percentage: savingsPercentage,
664→            isAchieved: currentSavings >= savingsGoal,
