666→        : null,
667→      categoryBreakdown,
668→      monthlyData,
669→      budgetAlerts,
670→      allBudgets,
671→      fixedExpenses,
672→      upcomingInstallments,
673→      weeklySummary,
674→      weeklyBreakdown,
675→    });
676→  } catch (error) {
677→    if (error instanceof Error && error.message === "Unauthorized") {
678→      return unauthorizedResponse();
679→    }
680→    console.error("Error fetching summary:", error);
681→    return NextResponse.json(
682→      { error: "Erro ao buscar resumo" },
