683→                  const today = new Date();
684→                  const weekStart = new Date(week.startDate);
685→                  const weekEnd = new Date(week.endDate);
686→
687→                  // Determinar se a semana é passada, atual ou futura
688→                  const isPastWeek = weekEnd < new Date(today.getFullYear(), today.getMonth(), today.getDate());
689→                  const isFutureWeek = weekStart > today;
690→                  const isCurrentWeek = !isPastWeek && !isFutureWeek;
691→
692→                  // Só considerar para maior/menor gasto as semanas que já passaram ou estão em andamento
693→                  const weeksForComparison = data.weeklyBreakdown!.weeks.filter((w) => {
694→                    const wEnd = new Date(w.endDate);
695→                    return wEnd <= today || (new Date(w.startDate) <= today && wEnd >= today);
696→                  });
697→
698→                  const maxTotal = Math.max(...data.weeklyBreakdown!.weeks.map((w) => w.total));
699→                  const percentage = maxTotal > 0 ? (week.total / maxTotal) * 100 : 0;
700→
