702→                  const minTotalPastCurrent = Math.min(...weeksForComparison.filter(w => w.total > 0).map((w) => w.total));
703→
704→                  const isHighest = !isFutureWeek && week.total === maxTotalPastCurrent && week.total > 0;
705→                  const isLowest = !isFutureWeek && week.total === minTotalPastCurrent && week.total > 0 && weeksForComparison.filter(w => w.total > 0).length > 1;
