735→                              Menor gasto
736→                            </Badge>
737→                          )}
738→                        </div>
739→                        <div className="text-right">
740→                          <span className={`font-semibold ${isFutureWeek ? "text-gray-500" : "text-red-600"}`}>
741→                            {formatCurrency(week.total)}
742→                          </span>
743→                          <span className="text-gray-500 text-xs ml-2">
744→                            ({week.count} transacoes)
745→                          </span>
746→                        </div>
747→                      </div>
748→                      <div className="relative h-8 rounded-lg bg-gray-100 overflow-hidden">
749→                        <div
750→                          className={`absolute left-0 top-0 h-full rounded-lg transition-all ${
751→                            isFutureWeek ? "bg-gray-300" :
752→                            isHighest ? "bg-red-400" :
753→                            isLowest ? "bg-green-400" :
754→                            isCurrentWeek ? "bg-indigo-500" : "bg-indigo-400"
755→                          }`}
756→                          style={{ width: `${percentage}%` }}
757→                        />
758→                        {/* Category breakdown inside bar */}
759→                        {week.categories.length > 0 && (
