768→                                  style={{ backgroundColor: cat.categoryColor }}
769→                                />
770→                                <span className="truncate max-w-[60px]">{cat.categoryName}</span>
771→                              </div>
772→                            ))}
773→                            {week.categories.length > 3 && (
774→                              <span className="text-xs text-white bg-black/20 rounded px-1.5 py-0.5">
775→                                +{week.categories.length - 3}
776→                              </span>
777→                            )}
778→                          </div>
779→                        )}
780→                      </div>
781→                    </div>
782→                  );
783→                })}
784→              </div>
785→
786→              {/* Summary */}
787→              <div className="pt-3 border-t flex justify-between items-center text-sm">
788→                <span className="text-gray-500">
789→                  Media por semana
