118→export async function POST(request: NextRequest) {
119→  try {
120→    const userId = await getAuthenticatedUserId();
121→    const body = await request.json();
122→    const {
123→      description,
124→      amount,
125→      date,
126→      type,
127→      origin,
128→      categoryId,
129→      isFixed,
130→      isInstallment,
131→      totalInstallments,
132→      installmentAmount,
133→      tags,
134→    } = body;
135→
136→    // Process tags - accept array or string, store as JSON string
137→    const processedTags = tags
138→      ? Array.isArray(tags)
139→        ? JSON.stringify(tags)
140→        : tags
141→      : null;
142→
143→    if (isInstallment && totalInstallments > 1) {
144→      // Create installment group and transactions
145→      const installment = await prisma.installment.create({
146→        data: {
147→          description,
148→          totalAmount: Math.abs(amount) * totalInstallments,
149→          totalInstallments,
150→          installmentAmount: installmentAmount || Math.abs(amount),
151→          startDate: new Date(date + "T12:00:00"),
152→          origin,
153→          userId,
154→        },
155→      });
156→
157→      const transactions = [];
158→      const startDate = new Date(date + "T12:00:00");
159→
160→      for (let i = 0; i < totalInstallments; i++) {
161→        const transactionDate = new Date(startDate);
162→        transactionDate.setMonth(transactionDate.getMonth() + i);
163→
164→        const transaction = await prisma.transaction.create({
165→          data: {
166→            description: `${description} (${i + 1}/${totalInstallments})`,
167→            amount: type === "EXPENSE" ? -Math.abs(installmentAmount || amount) : Math.abs(installmentAmount || amount),
168→            date: transactionDate,
169→            type,
170→            origin,
171→            categoryId: categoryId || null,
172→            isFixed: false,
173→            isInstallment: true,
174→            installmentId: installment.id,
175→            currentInstallment: i + 1,
176→            tags: processedTags,
177→            userId,
178→          },
179→          include: {
180→            category: true,
181→            installment: true,
182→          },
183→        });
184→        transactions.push(transaction);
185→      }
186→
187→      return NextResponse.json(transactions[0], { status: 201 });
188→    } else {
189→      const transaction = await prisma.transaction.create({
190→        data: {
191→          description,
192→          amount: type === "EXPENSE" ? -Math.abs(amount) : Math.abs(amount),
193→          date: new Date(date + "T12:00:00"),
194→          type,
195→          origin,
196→          categoryId: categoryId || null,
197→          isFixed: isFixed || false,
198→          isInstallment: false,
199→          tags: processedTags,
200→          userId,
201→        },
202→        include: {
203→          category: true,
204→        },
205→      });
206→
207→      return NextResponse.json(transaction, { status: 201 });
208→    }
209→  } catch (error) {
210→    if (error instanceof Error && error.message === "Unauthorized") {
211→      return unauthorizedResponse();
212→    }
213→    console.error("Error creating transaction:", error);
214→    return NextResponse.json(
215→      { error: "Erro ao criar transacao" },
216→      { status: 500 }
217→    );
218→  }
219→}
