  1→import { NextRequest, NextResponse } from "next/server";
  2→import prisma from "@/lib/db";
  3→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  4→
  5→export async function POST(
  6→  request: NextRequest,
  7→  { params }: { params: Promise<{ id: string }> }
  8→) {
  9→  try {
 10→    const userId = await getAuthenticatedUserId();
 11→    const { id } = await params;
 12→    const body = await request.json();
 13→    const { amount, date, notes } = body;
 14→
 15→    // Validate required fields
 16→    if (!amount || amount <= 0) {
 17→      return NextResponse.json(
 18→        { error: "Valor do aporte deve ser maior que zero" },
 19→        { status: 400 }
 20→      );
 21→    }
 22→
 23→    // Verify investment belongs to user
 24→    const existingInvestment = await prisma.investment.findFirst({
 25→      where: { id, userId },
 26→    });
 27→
 28→    if (!existingInvestment) {
 29→      return NextResponse.json(
 30→        { error: "Investimento nao encontrado" },
 31→        { status: 404 }
 32→      );
 33→    }
 34→
 35→    // Find "Investimentos" category - first try user's own, then global default
 36→    let investmentCategory = await prisma.category.findFirst({
 37→      where: {
 38→        userId,
 39→        name: { contains: "Investimento", mode: "insensitive" },
 40→      },
 41→    });
 42→
 43→    if (!investmentCategory) {
 44→      investmentCategory = await prisma.category.findFirst({
 45→        where: {
 46→          userId: null,
 47→          name: { contains: "Investimento", mode: "insensitive" },
 48→        },
 49→      });
 50→    }
 51→
 52→    const transactionDate = date ? new Date(date + "T12:00:00") : new Date();
 53→
 54→    // Use transaction for atomicity
 55→    const result = await prisma.$transaction(async (tx) => {
 56→      // 1. Create the cash flow Transaction (EXPENSE - money going out of account)
 57→      const transaction = await tx.transaction.create({
 58→        data: {
 59→          description: `Aporte - ${existingInvestment.name}`,
 60→          amount: -Math.abs(amount), // EXPENSE is negative
 61→          date: transactionDate,
 62→          type: "EXPENSE",
 63→          origin: existingInvestment.broker || "Investimento",
 64→          categoryId: investmentCategory?.id || null,
 65→          isFixed: false,
 66→          userId,
 67→        },
 68→      });
 69→
 70→      // 2. Create the InvestmentTransaction (DEPOSIT) linked to transaction
 71→      const investmentTransaction = await tx.investmentTransaction.create({
 72→        data: {
 73→          investmentId: id,
 74→          type: "DEPOSIT",
 75→          amount: Math.abs(amount),
 76→          date: transactionDate,
 77→          notes: notes || null,
 78→          linkedTransactionId: transaction.id,
 79→        },
 80→      });
 81→
 82→      // 3. Update Investment: currentValue += amount, totalInvested += amount
 83→      const updatedInvestment = await tx.investment.update({
 84→        where: { id },
 85→        data: {
 86→          currentValue: existingInvestment.currentValue + Math.abs(amount),
 87→          totalInvested: existingInvestment.totalInvested + Math.abs(amount),
 88→        },
 89→        include: {
 90→          category: true,
 91→        },
 92→      });
 93→
 94→      return {
 95→        investment: updatedInvestment,
 96→        investmentTransaction,
 97→        transaction,
 98→      };
 99→    });
100→
101→    return NextResponse.json(result, { status: 201 });
102→  } catch (error) {
103→    if (error instanceof Error && error.message === "Unauthorized") {
104→      return unauthorizedResponse();
105→    }
106→    console.error("Error creating deposit:", error);
107→    return NextResponse.json(
108→      { error: "Erro ao registrar aporte" },
109→      { status: 500 }
110→    );
111→  }
112→}
