 11→    const { id } = await params;
 12→    const body = await request.json();
 13→    const { amount, date, notes } = body;
 14→
 15→    // Validate required fields
 16→    if (!amount || amount <= 0) {
 17→      return NextResponse.json(
 18→        { error: "Valor do resgate deve ser maior que zero" },
 19→        { status: 400 }
 20→      );
 21→    }
 22→
 23→    // Verify investment belongs to user
 24→    const existingInvestment = await prisma.investment.findFirst({
 25→      where: { id, userId },
 26→    });
 27→
 28→    if (!existingInvestment) {
 29→      return NextResponse.json(
 30→        { error: "Investimento nao encontrado" },
 31→        { status: 404 }
 32→      );
 33→    }
 34→
 35→    // Validate: amount <= currentValue
 36→    if (amount > existingInvestment.currentValue) {
 37→      return NextResponse.json(
 38→        { error: "Valor do resgate nao pode ser maior que o valor atual do investimento" },
 39→        { status: 400 }
 40→      );
 41→    }
 42→
 43→    // Find "Investimentos" category - first try user's own, then global default
 44→    let investmentCategory = await prisma.category.findFirst({
 45→      where: {
 46→        userId,
 47→        name: { contains: "Investimento", mode: "insensitive" },
 48→      },
 49→    });
 50→
 51→    if (!investmentCategory) {
 52→      investmentCategory = await prisma.category.findFirst({
 53→        where: {
 54→          userId: null,
 55→          name: { contains: "Investimento", mode: "insensitive" },
 56→        },
 57→      });
 58→    }
 59→
 60→    const transactionDate = date ? new Date(date + "T12:00:00") : new Date();
 61→
 62→    // Use transaction for atomicity
 63→    const result = await prisma.$transaction(async (tx) => {
 64→      // 1. Create the cash flow Transaction (INCOME - money coming back to account)
 65→      const transaction = await tx.transaction.create({
 66→        data: {
 67→          description: `Resgate - ${existingInvestment.name}`,
 68→          amount: Math.abs(amount), // INCOME is positive
 69→          date: transactionDate,
 70→          type: "INCOME",
 71→          origin: existingInvestment.broker || "Investimento",
 72→          categoryId: investmentCategory?.id || null,
 73→          isFixed: false,
 74→          userId,
 75→        },
 76→      });
 77→
 78→      // 2. Create the InvestmentTransaction (WITHDRAWAL) linked to transaction
 79→      const investmentTransaction = await tx.investmentTransaction.create({
 80→        data: {
 81→          investmentId: id,
 82→          type: "WITHDRAWAL",
 83→          amount: Math.abs(amount),
 84→          date: transactionDate,
 85→          notes: notes || null,
 86→          linkedTransactionId: transaction.id,
 87→        },
 88→      });
 89→
 90→      // 3. Update Investment: currentValue -= amount, totalWithdrawn += amount
 91→      const updatedInvestment = await tx.investment.update({
 92→        where: { id },
 93→        data: {
 94→          currentValue: existingInvestment.currentValue - Math.abs(amount),
 95→          totalWithdrawn: existingInvestment.totalWithdrawn + Math.abs(amount),
 96→        },
 97→        include: {
 98→          category: true,
 99→        },
100→      });
101→
102→      return {
103→        investment: updatedInvestment,
104→        investmentTransaction,
105→        transaction,
106→      };
107→    });
108→
109→    return NextResponse.json(result, { status: 201 });
110→  } catch (error) {
111→    if (error instanceof Error && error.message === "Unauthorized") {
112→      return unauthorizedResponse();
113→    }
114→    console.error("Error creating withdrawal:", error);
115→    return NextResponse.json(
116→      { error: "Erro ao registrar resgate" },
117→      { status: 500 }
118→    );
119→  }
