  6→export async function GET(request: NextRequest) {
  7→  try {
  8→    const userId = await getAuthenticatedUserId();
  9→    const searchParams = request.nextUrl.searchParams;
 10→    const yearParam = searchParams.get("year");
 11→    const year = yearParam ? parseInt(yearParam, 10) : new Date().getFullYear();
 12→
 13→    const [currentYearTx, prevYearTx] = await Promise.all([
 14→      prisma.transaction.findMany({
 15→        where: {
 16→          userId,
 17→          deletedAt: null,
 18→          date: {
 19→            gte: new Date(year, 0, 1),
 20→            lte: new Date(year, 11, 31, 23, 59, 59, 999),
 21→          },
 22→        },
 23→      }),
 24→      prisma.transaction.findMany({
 25→        where: {
 26→          userId,
 27→          deletedAt: null,
 28→          date: {
 29→            gte: new Date(year - 1, 0, 1),
 30→            lte: new Date(year - 1, 11, 31, 23, 59, 59, 999),
 31→          },
 32→        },
 33→      }),
 34→    ]);
 35→
 36→    // Group current year by month
 37→    const currentByMonth: Record<number, { income: number; expense: number }> = {};
 38→    for (let m = 1; m <= 12; m++) {
 39→      currentByMonth[m] = { income: 0, expense: 0 };
 40→    }
 41→    for (const t of currentYearTx) {
 42→      const m = new Date(t.date).getMonth() + 1;
 43→      if (t.type === "INCOME") {
 44→        currentByMonth[m].income += Math.abs(t.amount);
 45→      } else if (t.type === "EXPENSE") {
 46→        currentByMonth[m].expense += Math.abs(t.amount);
 47→      }
 48→    }
 49→
 50→    // Group previous year by month
 51→    const prevByMonth: Record<number, { income: number; expense: number }> = {};
 52→    for (let m = 1; m <= 12; m++) {
 53→      prevByMonth[m] = { income: 0, expense: 0 };
 54→    }
 55→    for (const t of prevYearTx) {
 56→      const m = new Date(t.date).getMonth() + 1;
 57→      if (t.type === "INCOME") {
 58→        prevByMonth[m].income += Math.abs(t.amount);
 59→      } else if (t.type === "EXPENSE") {
 60→        prevByMonth[m].expense += Math.abs(t.amount);
 61→      }
 62→    }
 63→
 64→    // Build months array
 65→    const months = [];
 66→    let totalIncome = 0;
 67→    let totalExpense = 0;
 68→    let totalPrevIncome = 0;
 69→    let totalPrevExpense = 0;
 70→
 71→    for (let m = 1; m <= 12; m++) {
 72→      const curr = currentByMonth[m];
 73→      const prev = prevByMonth[m];
 74→
 75→      const incomeChange = prev.income > 0
 76→        ? ((curr.income - prev.income) / prev.income) * 100
 77→        : 0;
 78→      const expenseChange = prev.expense > 0
 79→        ? ((curr.expense - prev.expense) / prev.expense) * 100
 80→        : 0;
 81→
 82→      months.push({
 83→        month: m,
 84→        monthLabel: MONTH_LABELS[m - 1],
 85→        income: curr.income,
 86→        expense: curr.expense,
 87→        prevIncome: prev.income,
 88→        prevExpense: prev.expense,
 89→        incomeChange,
 90→        expenseChange,
 91→      });
 92→
 93→      totalIncome += curr.income;
 94→      totalExpense += curr.expense;
 95→      totalPrevIncome += prev.income;
 96→      totalPrevExpense += prev.expense;
 97→    }
 98→
 99→    return NextResponse.json({
100→      months,
101→      totals: {
102→        income: totalIncome,
103→        expense: totalExpense,
104→        prevIncome: totalPrevIncome,
105→        prevExpense: totalPrevExpense,
106→      },
107→    });
108→  } catch (error) {
109→    if (error instanceof Error && error.message === "Unauthorized") {
110→      return unauthorizedResponse();
111→    }
112→    console.error("Error fetching annual data:", error);
113→    return NextResponse.json(
114→      { error: "Erro ao buscar dados anuais" },
115→      { status: 500 }
116→    );
117→  }
118→}
