 26→export async function GET(request: NextRequest) {
 27→  try {
 28→    const userId = await getAuthenticatedUserId();
 29→    const searchParams = request.nextUrl.searchParams;
 30→    const monthsParam = searchParams.get("months");
 31→    const numMonths = monthsParam ? Math.min(Math.max(parseInt(monthsParam), 1), 12) : 6;
 32→
 33→    const now = new Date();
 34→    const startOfCurrentMonth = new Date(now.getFullYear(), now.getMonth(), 1);
 35→    const endDate = new Date(now.getFullYear(), now.getMonth() + numMonths, 0);
 36→
 37→    // Fetch future installment transactions (from grouped installments)
 38→    const futureInstallments = await prisma.transaction.findMany({
 39→      where: {
 40→        userId,
 41→        isInstallment: true,
 42→        installmentId: { not: null }, // Only grouped installments
 43→        date: {
 44→          gte: startOfCurrentMonth,
 45→          lte: endDate,
 46→        },
 47→      },
 48→      include: {
 49→        installment: true,
 50→      },
 51→      orderBy: { date: "asc" },
 52→    });
 53→
 54→    // Fetch standalone installments (manually marked, without group)
 55→    // These need to have their future installments projected
 56→    const standaloneInstallments = await prisma.transaction.findMany({
 57→      where: {
 58→        userId,
 59→        isInstallment: true,
 60→        installmentId: null,
 61→        totalInstallments: { not: null },
 62→        currentInstallment: { not: null },
 63→      },
 64→    });
 65→
 66→    // Project future installments from standalone transactions
 67→    interface ProjectedInstallment {
 68→      description: string;
 69→      amount: number;
 70→      date: Date;
 71→      currentInstallment: number;
 72→      totalInstallments: number;
 73→    }
 74→
 75→    const projectedStandaloneInstallments: ProjectedInstallment[] = [];
 76→    standaloneInstallments.forEach((t) => {
 77→      if (!t.currentInstallment || !t.totalInstallments) return;
 78→
 79→      const remainingInstallments = t.totalInstallments - t.currentInstallment;
 80→      const transactionDate = new Date(t.date);
 81→
 82→      for (let i = 1; i <= remainingInstallments; i++) {
 83→        const futureDate = new Date(transactionDate);
 84→        futureDate.setMonth(transactionDate.getMonth() + i);
 85→
 86→        // Only include if within projection range
 87→        if (futureDate >= startOfCurrentMonth && futureDate <= endDate) {
 88→          projectedStandaloneInstallments.push({
 89→            description: t.description,
 90→            amount: Math.abs(t.amount),
 91→            date: futureDate,
 92→            currentInstallment: t.currentInstallment + i,
 93→            totalInstallments: t.totalInstallments,
 94→          });
 95→        }
 96→      }
 97→    });
 98→
 99→    // Fetch active recurring expenses/incomes
100→    const activeRecurring = await prisma.recurringExpense.findMany({
101→      where: {
102→        userId,
103→        isActive: true,
104→      },
105→    });
106→
107→    // For each recurring, find the most recent transaction to get the latest amount
108→    // (in case user edited the value)
109→    const recurringWithLatestAmount = await Promise.all(
110→      activeRecurring.map(async (recurring) => {
111→        const latestTransaction = await prisma.transaction.findFirst({
112→          where: {
113→            userId,
114→            recurringExpenseId: recurring.id,
115→          },
116→          orderBy: { date: "desc" },
117→          select: { amount: true },
118→        });
119→
120→        return {
121→          ...recurring,
122→          // Use the latest transaction amount if exists, otherwise use defaultAmount
123→          effectiveAmount: latestTransaction?.amount ?? recurring.defaultAmount,
124→        };
125→      })
126→    );
127→
128→    // Fetch all actual transactions for current month (for real expenses calculation)
129→    const endOfCurrentMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0);
130→    const currentMonthTransactions = await prisma.transaction.findMany({
131→      where: {
132→        userId,
133→        date: {
134→          gte: startOfCurrentMonth,
135→          lte: endOfCurrentMonth,
136→        },
137→        deletedAt: null,
138→      },
139→    });
140→
141→    // Calculate actual expenses and income for current month
142→    const actualExpenses = currentMonthTransactions
143→      .filter((t) => t.type === "EXPENSE")
144→      .reduce((sum, t) => sum + Math.abs(t.amount), 0);
145→
146→    const actualIncome = currentMonthTransactions
147→      .filter((t) => t.type === "INCOME")
148→      .reduce((sum, t) => sum + Math.abs(t.amount), 0);
149→
150→    // Find which recurring expenses have already been charged this month
151→    const chargedRecurringIds = new Set(
152→      currentMonthTransactions
153→        .filter((t) => t.recurringExpenseId !== null)
154→        .map((t) => t.recurringExpenseId)
155→    );
156→
157→    // Filter recurring to only include those NOT yet charged (for current month projection)
158→    const pendingRecurring = recurringWithLatestAmount.filter(
159→      (r) => !chargedRecurringIds.has(r.id)
160→    );
161→
162→    // Build monthly projections
163→    const months: MonthProjection[] = [];
164→    let totalInstallmentsSum = 0;
165→    let totalRecurringExpensesSum = 0;
166→    let totalRecurringIncomeSum = 0;
167→    let totalActualExpensesSum = 0;
168→    let totalActualIncomeSum = 0;
169→
170→    for (let i = 0; i < numMonths; i++) {
171→      const isCurrentMonth = i === 0;
172→      const projMonth = now.getMonth() + i;
173→      const projYear = now.getFullYear() + Math.floor(projMonth / 12);
174→      const normalizedMonth = (projMonth % 12) + 1;
175→
176→      const monthLabel = `${MONTH_LABELS[normalizedMonth - 1]}/${String(projYear).slice(-2)}`;
177→
178→      // Get grouped installments for this month
179→      const monthInstallments = futureInstallments.filter((t) => {
180→        const tDate = new Date(t.date);
181→        return tDate.getMonth() + 1 === normalizedMonth && tDate.getFullYear() === projYear;
182→      });
183→
184→      // Get projected standalone installments for this month
185→      const monthStandaloneInstallments = projectedStandaloneInstallments.filter((t) => {
186→        return t.date.getMonth() + 1 === normalizedMonth && t.date.getFullYear() === projYear;
187→      });
188→
189→      const installmentItems: ProjectionInstallmentItem[] = [
190→        // From grouped installments
191→        ...monthInstallments.map((t) => ({
192→          description: t.description,
193→          amount: Math.abs(t.amount),
194→          currentInstallment: t.currentInstallment || 1,
195→          totalInstallments: t.installment?.totalInstallments || 1,
196→        })),
197→        // From projected standalone installments
198→        ...monthStandaloneInstallments.map((t) => ({
199→          description: t.description,
200→          amount: t.amount,
201→          currentInstallment: t.currentInstallment,
202→          totalInstallments: t.totalInstallments,
203→        })),
204→      ];
205→
206→      const installmentsTotal =
207→        monthInstallments.reduce((sum, t) => sum + Math.abs(t.amount), 0) +
208→        monthStandaloneInstallments.reduce((sum, t) => sum + t.amount, 0);
209→      totalInstallmentsSum += installmentsTotal;
210→
211→      // For current month: use only pending recurring (not yet charged)
212→      // For future months: use all recurring
213→      const recurringToUse = isCurrentMonth ? pendingRecurring : recurringWithLatestAmount;
214→
215→      const recurringItems: ProjectionRecurringItem[] = recurringToUse.map((r) => ({
216→        description: r.description,
217→        amount: Math.abs(r.effectiveAmount),
218→        type: r.type as "INCOME" | "EXPENSE",
219→      }));
220→
221→      const recurringExpensesPending = recurringToUse
222→        .filter((r) => r.type === "EXPENSE")
223→        .reduce((sum, r) => sum + Math.abs(r.effectiveAmount), 0);
224→
225→      const recurringIncomePending = recurringToUse
226→        .filter((r) => r.type === "INCOME")
227→        .reduce((sum, r) => sum + Math.abs(r.effectiveAmount), 0);
228→
229→      // For current month: actual + pending recurring
230→      // For future months: just projected recurring
231→      const monthActualExpenses = isCurrentMonth ? actualExpenses : 0;
232→      const monthActualIncome = isCurrentMonth ? actualIncome : 0;
233→
234→      totalActualExpensesSum += monthActualExpenses;
235→      totalActualIncomeSum += monthActualIncome;
236→      totalRecurringExpensesSum += recurringExpensesPending;
237→      totalRecurringIncomeSum += recurringIncomePending;
238→
239→      // Total expenses = actual expenses (current month) + pending recurring expenses
240→      // For current month, installments are already included in actual expenses if they exist
241→      // For future months, we add installments separately
242→      let totalExpenses: number;
243→      let totalIncome: number;
244→
245→      if (isCurrentMonth) {
246→        // Actual already includes what was spent (including any installments/recurring already charged)
247→        // Add only pending recurring
248→        totalExpenses = monthActualExpenses + recurringExpensesPending;
249→        totalIncome = monthActualIncome + recurringIncomePending;
250→      } else {
251→        // Future months: installments + all recurring
252→        totalExpenses = installmentsTotal + recurringExpensesPending;
253→        totalIncome = recurringIncomePending;
254→      }
255→
256→      const projectedBalance = totalIncome - totalExpenses;
257→
258→      months.push({
259→        month: normalizedMonth,
260→        year: projYear,
261→        monthLabel,
262→        isCurrentMonth,
263→        actualExpenses: monthActualExpenses,
264→        actualIncome: monthActualIncome,
265→        installmentsTotal,
266→        installmentsCount: monthInstallments.length + monthStandaloneInstallments.length,
267→        installments: installmentItems,
268→        recurringExpenses: recurringExpensesPending,
269→        recurringIncome: recurringIncomePending,
270→        recurringItems,
271→        totalExpenses,
272→        totalIncome,
273→        projectedBalance,
274→        isNegative: projectedBalance < 0,
275→      });
276→    }
277→
278→    const response: ProjectionResponse = {
279→      months,
280→      totals: {
281→        totalInstallments: totalInstallmentsSum,
282→        totalRecurringExpenses: totalRecurringExpensesSum,
283→        totalRecurringIncome: totalRecurringIncomeSum,
284→        netProjectedBalance: totalRecurringIncomeSum - totalInstallmentsSum - totalRecurringExpensesSum,
285→      },
286→    };
287→
288→    return NextResponse.json(response);
289→  } catch (error) {
290→    if (error instanceof Error && error.message === "Unauthorized") {
291→      return unauthorizedResponse();
292→    }
293→    console.error("Error fetching projection:", error);
294→    return NextResponse.json(
295→      { error: "Erro ao buscar projecao financeira" },
296→      { status: 500 }
297→    );
298→  }
299→}
