 34→export async function POST(request: NextRequest) {
 35→  try {
 36→    const userId = await getAuthenticatedUserId();
 37→    const body = await request.json();
 38→    const { transactions, origin } = body;
 39→
 40→    if (!transactions || !Array.isArray(transactions)) {
 41→      return NextResponse.json(
 42→        { error: "Transacoes invalidas" },
 43→        { status: 400 }
 44→      );
 45→    }
 46→
 47→    // Fetch ALL active recurring expenses for matching (not just autoGenerate=false)
 48→    const recurringToMatch = await prisma.recurringExpense.findMany({
 49→      where: {
 50→        userId,
 51→        isActive: true,
 52→      },
 53→      include: {
 54→        transactions: {
 55→          select: { id: true, date: true },
 56→          where: { deletedAt: null },
 57→        },
 58→      },
 59→    });
 60→
 61→    // Fetch user's category tags for validation
 62→    const userTagIds = new Set(
 63→      (await prisma.categoryTag.findMany({
 64→        where: { userId },
 65→        select: { id: true, categoryId: true },
 66→      })).map(t => `${t.id}:${t.categoryId}`)
 67→    );
 68→
 69→    const created = [];
 70→    let linkedCount = 0;
 71→    let carryoverLinkedCount = 0;
 72→    const linkedCarryovers: Array<{
 73→      transactionId: string;
 74→      billPaymentId: string;
 75→      fromBill: string;
 76→      interestRate: number | null;
 77→      interestAmount: number | null;
 78→    }> = [];
 79→
 80→    for (const t of transactions) {
 81→      // Determine type and amount sign
 82→      const type = t.type || "EXPENSE";
 83→      let amount = t.amount;
 84→
 85→      // Ensure amount sign matches type
 86→      if (type === "EXPENSE" && amount > 0) {
 87→        amount = -amount;
 88→      } else if (type === "INCOME" && amount < 0) {
 89→        amount = Math.abs(amount);
 90→      }
 91→
 92→      // Parse date safely to avoid timezone issues with YYYY-MM-DD format
 93→      const dateStr = typeof t.date === 'string' && !t.date.includes('T')
 94→        ? t.date + 'T12:00:00'
 95→        : t.date;
 96→      const transactionDate = new Date(dateStr);
 97→      const transactionMonth = transactionDate.getMonth();
 98→      const transactionYear = transactionDate.getFullYear();
 99→      const transactionOrigin = origin || t.origin || "Importacao CSV";
100→
101→      // Try to match with a recurring expense
102→      let matchedRecurringId: string | null = null;
103→
104→      // Validate frontend-provided recurringExpenseId belongs to this user
105→      if (t.recurringExpenseId) {
106→        const isOwned = recurringToMatch.some(r => r.id === t.recurringExpenseId);
107→        if (isOwned) {
108→          matchedRecurringId = t.recurringExpenseId;
109→        }
110→      }
111→
112→      // Only do server-side matching if no valid match from frontend
113→      if (!matchedRecurringId) {
114→        const matches = recurringToMatch.filter((recurring) => {
115→          // Check origin match
116→          if (recurring.origin !== transactionOrigin) {
117→            return false;
118→          }
119→
120→          // Check category match (if recurring has category defined)
121→          if (recurring.categoryId && t.categoryId && recurring.categoryId !== t.categoryId) {
122→            return false;
123→          }
124→
125→          // Check description match
126→          if (!matchesRecurring(t.description, recurring.description)) {
127→            return false;
128→          }
129→
130→          // Check if already has transaction for this month
131→          const hasThisMonth = recurring.transactions.some((existingTx) => {
132→            const existingDate = new Date(existingTx.date);
133→            return (
134→              existingDate.getMonth() === transactionMonth &&
135→              existingDate.getFullYear() === transactionYear
136→            );
137→          });
138→
139→          if (hasThisMonth) {
140→            return false;
141→          }
142→
143→          return true;
144→        });
145→
146→        // Only link if we have exactly one match (conservative)
147→        if (matches.length === 1) {
148→          matchedRecurringId = matches[0].id;
149→          // Add to existing transactions to prevent double matching in same import
150→          matches[0].transactions.push({ id: "temp", date: transactionDate });
151→          linkedCount++;
152→        }
153→      } else {
154→        linkedCount++;
155→      }
156→
157→      // Validate frontend-provided categoryTagId belongs to user and matches category
158→      let validatedTagId: string | null = null;
159→      if (t.categoryTagId) {
160→        const tagKey = `${t.categoryTagId}:${t.categoryId || ""}`;
161→        if (userTagIds.has(tagKey)) {
162→          validatedTagId = t.categoryTagId;
163→        }
164→      }
165→
166→      const transaction = await prisma.transaction.create({
167→        data: {
168→          userId,
169→          description: t.description,
170→          amount,
171→          date: transactionDate,
172→          type,
173→          origin: transactionOrigin,
174→          categoryId: t.categoryId || null,
175→          categoryTagId: validatedTagId,
176→          isFixed: matchedRecurringId !== null,
177→          isInstallment: t.isInstallment || false,
178→          currentInstallment: t.currentInstallment || null,
179→          totalInstallments: t.totalInstallments || null,
180→          recurringExpenseId: matchedRecurringId,
181→        },
182→        include: {
183→          category: true,
184→          recurringExpense: true,
185→        },
186→      });
187→      created.push(transaction);
188→
189→      // Check if this is a carryover transaction and try to link it to a BillPayment
190→      if (isCarryoverTransaction(t.description)) {
191→        try {
192→          const matchingBillPayment = await findMatchingBillPayment({
193→            origin: transactionOrigin,
194→            month: transactionMonth + 1, // Convert from 0-indexed to 1-indexed
195→            year: transactionYear,
196→            amount: Math.abs(amount),
197→            userId,
198→          });
199→
200→          if (matchingBillPayment) {
201→            // Calculate interest from the difference
202→            const interest = calculateInterest(
203→              matchingBillPayment.amountCarried,
204→              Math.abs(amount)
205→            );
206→
207→            // Update the BillPayment with the linked transaction and interest info
208→            await prisma.billPayment.update({
209→              where: { id: matchingBillPayment.id },
210→              data: {
211→                linkedTransactionId: transaction.id,
212→                interestRate: interest.rate,
213→                interestAmount: interest.amount,
214→              },
215→            });
216→
217→            // Soft delete the old carryover transaction if it exists
218→            if (matchingBillPayment.carryoverTransactionId) {
219→              await prisma.transaction.update({
220→                where: { id: matchingBillPayment.carryoverTransactionId },
221→                data: { deletedAt: new Date() },
222→              });
223→            }
224→
225→            carryoverLinkedCount++;
226→            linkedCarryovers.push({
227→              transactionId: transaction.id,
228→              billPaymentId: matchingBillPayment.id,
229→              fromBill: `${matchingBillPayment.billMonth}/${matchingBillPayment.billYear}`,
230→              interestRate: interest.rate,
231→              interestAmount: interest.amount,
232→            });
233→          }
234→        } catch (carryoverError) {
235→          // Log but don't fail the import if carryover linking fails
236→          console.error("Error linking carryover transaction:", carryoverError);
237→        }
238→      }
239→    }
240→
241→    // Build response message
242→    const messageParts = [`${created.length} transacoes importadas`];
243→    if (linkedCount > 0) {
244→      messageParts.push(`${linkedCount} vinculadas a recorrentes`);
245→    }
246→    if (carryoverLinkedCount > 0) {
247→      messageParts.push(`${carryoverLinkedCount} vinculadas a saldo rolado`);
248→    }
249→    const message =
250→      linkedCount > 0 || carryoverLinkedCount > 0
251→        ? `${messageParts[0]} (${messageParts.slice(1).join(", ")})`
252→        : `${created.length} transacoes importadas com sucesso`;
253→
254→    return NextResponse.json(
255→      {
256→        message,
257→        count: created.length,
258→        linkedCount,
259→        carryoverLinkedCount,
260→        linkedCarryovers,
261→      },
262→      { status: 201 }
263→    );
264→  } catch (error) {
265→    if (error instanceof Error && error.message === "Unauthorized") {
266→      return unauthorizedResponse();
267→    }
268→    console.error("Error importing transactions:", error);
269→    return NextResponse.json(
270→      { error: "Erro ao importar transacoes" },
271→      { status: 500 }
272→    );
273→  }
274→}
