  1→import { NextRequest, NextResponse } from "next/server";
  2→import { Prisma } from "@prisma/client";
  3→import prisma from "@/lib/db";
  4→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  5→
  6→interface TransactionToCheck {
  7→  description: string;
  8→  amount: number;
  9→  date: string;
 10→  origin?: string;
 11→  isInstallment?: boolean;
 12→  currentInstallment?: number;
 13→  totalInstallments?: number;
 14→}
 15→
 16→interface RelatedInstallment {
 17→  index: number;
 18→  relatedTransactionId: string;
 19→  relatedDescription: string;
 20→  relatedInstallment: number;
 21→}
 22→
 23→// Extract base description without installment info
 24→// "GRANADO PHARMACIES - Parcela 2/2" -> "GRANADO PHARMACIES"
 25→function extractBaseDescription(description: string): string {
 26→  return description
 27→    .replace(/\s*[-–]\s*Parcela\s*\d+\s*[\/\\]\s*\d+/i, "")
 28→    .replace(/\s*\(\d+\s*[\/\\]\s*\d+\)\s*$/i, "")
 29→    .replace(/\s*Parcela\s*\d+\s*[\/\\]\s*\d+/i, "")
 30→    .replace(/\s*\d+\s*[\/\\]\s*\d+\s*$/i, "")
 31→    .trim();
 32→}
 33→
 34→// Detect installment from description
 35→function detectInstallmentFromDescription(description: string): { current: number; total: number } | null {
 36→  const patterns = [
 37→    /[-–]\s*Parcela\s+(\d+)\s*[\/\\]\s*(\d+)/i,
 38→    /Parcela\s+(\d+)\s*[\/\\]\s*(\d+)/i,
 39→    /\((\d+)\s*[\/\\]\s*(\d+)\)/,
 40→    /(\d+)\s*[\/\\]\s*(\d+)/,
 41→  ];
 42→
 43→  for (const pattern of patterns) {
 44→    const match = description.match(pattern);
 45→    if (match) {
 46→      const current = parseInt(match[1], 10);
 47→      const total = parseInt(match[2], 10);
 48→      if (current > 0 && total > 1 && current <= total && total <= 48) {
 49→        return { current, total };
 50→      }
 51→    }
 52→  }
 53→  return null;
 54→}
 55→
 56→export async function POST(request: NextRequest) {
 57→  try {
 58→    const userId = await getAuthenticatedUserId();
 59→
 60→    const body = await request.json();
 61→    const { transactions, origin } = body as { transactions: TransactionToCheck[]; origin?: string };
 62→
 63→    if (!transactions || !Array.isArray(transactions)) {
 64→      return NextResponse.json(
 65→        { error: "Transacoes nao fornecidas" },
 66→        { status: 400 }
 67→      );
 68→    }
 69→
 70→    const duplicates: number[] = [];
 71→    const relatedInstallments: RelatedInstallment[] = [];
 72→
 73→    for (let i = 0; i < transactions.length; i++) {
 74→      const t = transactions[i];
 75→      // Parse date safely to avoid timezone issues with YYYY-MM-DD format
 76→      const dateStr = !t.date.includes('T') ? t.date + 'T12:00:00' : t.date;
 77→      const transactionDate = new Date(dateStr);
 78→
 79→      // Check for exact duplicates (same date, description, amount, and optionally origin)
 80→      const duplicateWhere: Prisma.TransactionWhereInput = {
 81→        userId,
 82→        description: {
 83→          contains: t.description.slice(0, 50),
 84→        },
 85→        amount: {
 86→          gte: t.amount - 0.01,
 87→          lte: t.amount + 0.01,
 88→        },
 89→        date: {
 90→          gte: new Date(transactionDate.getTime() - 24 * 60 * 60 * 1000),
 91→          lte: new Date(transactionDate.getTime() + 24 * 60 * 60 * 1000),
 92→        },
 93→        deletedAt: null,
 94→        ...(origin ? { origin } : {}),
 95→      };
 96→
 97→      const existing = await prisma.transaction.findFirst({
 98→        where: duplicateWhere,
 99→      });
100→
101→      if (existing) {
102→        duplicates.push(i);
103→        continue;
104→      }
105→
106→      // Also check if a recurring expense already has a transaction for this month
107→      // that is linked to a recurring expense (via recurringExpenseId)
108→      if (!existing && origin) {
109→        const recurringDuplicates = await prisma.transaction.findMany({
110→          where: {
111→            userId,
112→            recurringExpenseId: { not: null },
113→            origin,
114→            date: {
115→              gte: new Date(transactionDate.getFullYear(), transactionDate.getMonth(), 1),
116→              lt: new Date(transactionDate.getFullYear(), transactionDate.getMonth() + 1, 1),
117→            },
118→            deletedAt: null,
119→          },
120→          include: { recurringExpense: true },
121→        });
122→
123→        // Check if any recurring transaction matches by keyword (reuse normalize+keyword logic)
124→        const normalizedDesc = t.description.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim();
125→        const isRecurringDuplicate = recurringDuplicates.some((rt) => {
126→          if (!rt.recurringExpense) return false;
127→          const keywords = rt.recurringExpense.description
128→            .toLowerCase()
129→            .normalize("NFD")
130→            .replace(/[\u0300-\u036f]/g, "")
131→            .trim()
132→            .split(/\s+/)
133→            .filter((k: string) => k.length > 2);
134→          return keywords.some((kw: string) => normalizedDesc.includes(kw));
135→        });
136→
137→        if (isRecurringDuplicate) {
138→          duplicates.push(i);
139→          continue;
140→        }
141→      }
142→
143→      // Check for related installments (sequential installments of same purchase)
144→      const installmentInfo = detectInstallmentFromDescription(t.description) ||
145→        (t.isInstallment && t.currentInstallment && t.totalInstallments
146→          ? { current: t.currentInstallment, total: t.totalInstallments }
147→          : null);
148→
149→      if (installmentInfo && installmentInfo.current > 1) {
150→        const baseDescription = extractBaseDescription(t.description);
151→
152→        // Look for the previous installment (current - 1)
153→        const previousInstallment = installmentInfo.current - 1;
154→
155→        // Search for transactions with similar base description that are installments
156→        const relatedTransaction = await prisma.transaction.findFirst({
157→          where: {
158→            userId,
159→            isInstallment: true,
160→            currentInstallment: previousInstallment,
161→            totalInstallments: installmentInfo.total,
162→            amount: {
163→              gte: t.amount - 1, // Allow small variance
164→              lte: t.amount + 1,
165→            },
166→            deletedAt: null,
167→          },
168→        });
169→
170→        // If not found by exact match, try by description similarity
171→        if (!relatedTransaction) {
172→          const similarTransactions = await prisma.transaction.findMany({
173→            where: {
174→              userId,
175→              isInstallment: true,
176→              totalInstallments: installmentInfo.total,
177→              amount: {
178→                gte: t.amount - 1,
179→                lte: t.amount + 1,
180→              },
181→              deletedAt: null,
182→            },
183→          });
184→
185→          // Find one with matching base description
186→          for (const st of similarTransactions) {
187→            const stBase = extractBaseDescription(st.description);
188→            if (
189→              stBase.toLowerCase().includes(baseDescription.toLowerCase().slice(0, 20)) ||
190→              baseDescription.toLowerCase().includes(stBase.toLowerCase().slice(0, 20))
191→            ) {
192→              if (st.currentInstallment === previousInstallment) {
193→                relatedInstallments.push({
194→                  index: i,
195→                  relatedTransactionId: st.id,
196→                  relatedDescription: st.description,
197→                  relatedInstallment: st.currentInstallment || 0,
198→                });
199→                break;
200→              }
201→            }
202→          }
203→        } else {
204→          relatedInstallments.push({
205→            index: i,
206→            relatedTransactionId: relatedTransaction.id,
207→            relatedDescription: relatedTransaction.description,
208→            relatedInstallment: relatedTransaction.currentInstallment || 0,
209→          });
210→        }
211→      }
212→    }
213→
214→    return NextResponse.json({
215→      duplicates,
216→      hasDuplicates: duplicates.length > 0,
217→      relatedInstallments,
218→      hasRelatedInstallments: relatedInstallments.length > 0,
219→    });
220→  } catch (error) {
221→    if (error instanceof Error && error.message === "Unauthorized") {
222→      return unauthorizedResponse();
223→    }
224→    console.error("Error checking duplicates:", error);
225→    return NextResponse.json(
226→      { error: "Erro ao verificar duplicatas" },
227→      { status: 500 }
228→    );
229→  }
230→}
