  1→import { NextRequest, NextResponse } from "next/server";
  2→import prisma from "@/lib/db";
  3→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  4→import { MONTH_LABELS } from "@/lib/constants";
  5→
  6→export async function GET(request: NextRequest) {
  7→  try {
  8→    const userId = await getAuthenticatedUserId();
  9→    const searchParams = request.nextUrl.searchParams;
 10→    const yearParam = searchParams.get("year");
 11→    const year = yearParam ? parseInt(yearParam, 10) : new Date().getFullYear();
 12→
 13→    const transactions = await prisma.transaction.findMany({
 14→      where: {
 15→        userId,
 16→        deletedAt: null,
 17→        type: "EXPENSE",
 18→        date: {
 19→          gte: new Date(year, 0, 1),
 20→          lte: new Date(year, 11, 31, 23, 59, 59, 999),
 21→        },
 22→      },
 23→      include: {
 24→        category: true,
 25→      },
 26→    });
 27→
 28→    // Group by category + month
 29→    const categoryMap: Record<
 30→      string,
 31→      {
 32→        categoryId: string;
 33→        categoryName: string;
 34→        categoryColor: string;
 35→        monthlyTotals: number[];
 36→        total: number;
 37→      }
 38→    > = {};
 39→
 40→    for (const t of transactions) {
 41→      if (!t.category || !t.categoryId) continue;
 42→
 43→      const month = new Date(t.date).getMonth(); // 0-11
 44→      const amount = Math.abs(t.amount);
 45→
 46→      if (!categoryMap[t.categoryId]) {
 47→        categoryMap[t.categoryId] = {
 48→          categoryId: t.categoryId,
 49→          categoryName: t.category.name,
 50→          categoryColor: t.category.color,
 51→          monthlyTotals: new Array(12).fill(0),
 52→          total: 0,
 53→        };
 54→      }
 55→
 56→      categoryMap[t.categoryId].monthlyTotals[month] += amount;
 57→      categoryMap[t.categoryId].total += amount;
 58→    }
 59→
 60→    // Calculate trend for each category
 61→    const categories = Object.values(categoryMap).map((cat) => {
 62→      // Average of first 3 months with data
 63→      const first3 = cat.monthlyTotals.slice(0, 3);
 64→      const avgFirst3 = first3.reduce((a, b) => a + b, 0) / 3;
 65→
 66→      // Average of last 3 months with data
 67→      const monthsWithData = cat.monthlyTotals
 68→        .map((val, idx) => ({ val, idx }))
 69→        .filter((m) => m.val > 0);
 70→      const last3Months = monthsWithData.slice(-3);
 71→      const avgLast3 =
 72→        last3Months.length > 0
 73→          ? last3Months.reduce((a, b) => a + b.val, 0) / last3Months.length
 74→          : 0;
 75→
 76→      const trend = avgFirst3 > 0
 77→        ? ((avgLast3 - avgFirst3) / avgFirst3) * 100
 78→        : 0;
 79→
 80→      return {
 81→        ...cat,
 82→        trend,
 83→      };
 84→    });
 85→
 86→    // Sort by total descending
 87→    categories.sort((a, b) => b.total - a.total);
 88→
 89→    // Find highlights
 90→    const categoriesWithTrend = categories.filter(
 91→      (c) => c.trend !== 0 && c.total > 0
 92→    );
 93→    const mostGrown = categoriesWithTrend.length > 0
 94→      ? categoriesWithTrend.reduce((max, c) =>
 95→          c.trend > max.trend ? c : max
 96→        )
 97→      : null;
 98→    const mostShrunk = categoriesWithTrend.length > 0
 99→      ? categoriesWithTrend.reduce((min, c) =>
100→          c.trend < min.trend ? c : min
101→        )
102→      : null;
103→
104→    return NextResponse.json({
105→      months: MONTH_LABELS,
106→      categories,
107→      highlights: {
108→        mostGrown: mostGrown
109→          ? { categoryName: mostGrown.categoryName, trend: mostGrown.trend }
110→          : null,
111→        mostShrunk: mostShrunk
112→          ? { categoryName: mostShrunk.categoryName, trend: mostShrunk.trend }
113→          : null,
114→      },
115→    });
116→  } catch (error) {
117→    if (error instanceof Error && error.message === "Unauthorized") {
118→      return unauthorizedResponse();
119→    }
120→    console.error("Error fetching category trends:", error);
121→    return NextResponse.json(
122→      { error: "Erro ao buscar tendencias de categorias" },
123→      { status: 500 }
124→    );
125→  }
126→}
