  1→import { NextRequest, NextResponse } from "next/server";
  2→import prisma from "@/lib/db";
  3→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  4→import { MONTH_LABELS } from "@/lib/constants";
  5→
  6→export async function GET(request: NextRequest) {
  7→  try {
  8→    const userId = await getAuthenticatedUserId();
  9→    const searchParams = request.nextUrl.searchParams;
 10→    const month = parseInt(searchParams.get("month") || String(new Date().getMonth() + 1), 10);
 11→    const year = parseInt(searchParams.get("year") || String(new Date().getFullYear()), 10);
 12→
 13→    // Calculate 12-month range ending at the given month
 14→    const endDate = new Date(year, month, 0); // last day of target month
 15→    // Start from 11 months before the target month (total of 12 months inclusive)
 16→    const startDate = new Date(year, month - 12, 1);
 17→
 18→    // Fetch 12 months of expense transactions
 19→    const transactions = await prisma.transaction.findMany({
 20→      where: {
 21→        userId,
 22→        deletedAt: null,
 23→        type: "EXPENSE",
 24→        date: {
 25→          gte: startDate,
 26→          lte: endDate,
 27→        },
 28→      },
 29→      select: {
 30→        description: true,
 31→        amount: true,
 32→        date: true,
 33→        isFixed: true,
 34→        categoryId: true,
 35→        category: {
 36→          select: {
 37→            name: true,
 38→          },
 39→        },
 40→      },
 41→      orderBy: {
 42→        date: "asc",
 43→      },
 44→    });
 45→
 46→    // Build monthly breakdown
 47→    const monthlyEntries: { key: string; label: string; fixed: number; variable: number }[] = [];
 48→    const entryMap = new Map<string, { key: string; label: string; fixed: number; variable: number }>();
 49→    for (let i = 0; i < 12; i++) {
 50→      const d = new Date(startDate);
 51→      d.setMonth(d.getMonth() + i);
 52→      const key = `${d.getFullYear()}-${d.getMonth()}`;
 53→      const label = `${MONTH_LABELS[d.getMonth()]}/${String(d.getFullYear()).slice(2)}`;
 54→      const entry = { key, label, fixed: 0, variable: 0 };
 55→      monthlyEntries.push(entry);
 56→      entryMap.set(key, entry);
 57→    }
 58→
 59→    // Aggregate transactions into monthly buckets
 60→    for (const t of transactions) {
 61→      const d = new Date(t.date);
 62→      const key = `${d.getFullYear()}-${d.getMonth()}`;
 63→      const entry = entryMap.get(key);
 64→      if (entry) {
 65→        const absAmount = Math.abs(t.amount);
 66→        if (t.isFixed) {
 67→          entry.fixed += absAmount;
 68→        } else {
 69→          entry.variable += absAmount;
 70→        }
 71→      }
 72→    }
 73→
 74→    const monthlyBreakdown = monthlyEntries.map((e) => ({
 75→      monthLabel: e.label,
 76→      fixed: e.fixed,
 77→      variable: e.variable,
 78→    }));
 79→
 80→    // Current month data
 81→    const currentMonthStart = new Date(year, month - 1, 1);
 82→    const currentMonthEnd = new Date(year, month, 0);
 83→    const currentMonthTransactions = transactions.filter((t) => {
 84→      const d = new Date(t.date);
 85→      return d >= currentMonthStart && d <= currentMonthEnd;
 86→    });
 87→
 88→    const fixed = currentMonthTransactions
 89→      .filter((t) => t.isFixed)
 90→      .reduce((sum, t) => sum + Math.abs(t.amount), 0);
 91→
 92→    const variable = currentMonthTransactions
 93→      .filter((t) => !t.isFixed)
 94→      .reduce((sum, t) => sum + Math.abs(t.amount), 0);
 95→
 96→    const total = fixed + variable;
 97→    const fixedPercentage = total > 0 ? (fixed / total) * 100 : 0;
 98→
 99→    // Distinct fixed expenses for current month
100→    const fixedTransactions = currentMonthTransactions.filter((t) => t.isFixed);
101→    const seenDescriptions = new Set<string>();
102→    const fixedExpenses: { description: string; amount: number; categoryName: string }[] = [];
103→
104→    for (const t of fixedTransactions) {
105→      if (!seenDescriptions.has(t.description)) {
106→        seenDescriptions.add(t.description);
107→        fixedExpenses.push({
108→          description: t.description,
109→          amount: Math.abs(t.amount),
110→          categoryName: t.category?.name || "Sem categoria",
111→        });
112→      }
113→    }
114→
115→    fixedExpenses.sort((a, b) => b.amount - a.amount);
116→
117→    // Top 10 variable expenses for current month
118→    const topVariableExpenses = currentMonthTransactions
119→      .filter((t) => !t.isFixed)
120→      .map((t) => ({
121→        description: t.description,
122→        amount: Math.abs(t.amount),
123→        categoryName: t.category?.name || "Sem categoria",
124→        date: new Date(t.date).toISOString().split("T")[0],
125→      }))
126→      .sort((a, b) => b.amount - a.amount)
127→      .slice(0, 10);
128→
129→    return NextResponse.json({
130→      currentMonth: {
131→        fixed,
132→        variable,
133→        total,
134→        fixedPercentage,
135→      },
136→      monthlyBreakdown,
137→      fixedExpenses,
138→      topVariableExpenses,
139→    });
140→  } catch (error) {
141→    if (error instanceof Error && error.message === "Unauthorized") {
142→      return unauthorizedResponse();
143→    }
144→    console.error("Error fetching fixed/variable data:", error);
145→    return NextResponse.json(
146→      { error: "Erro ao buscar dados fixos/variaveis" },
147→      { status: 500 }
148→    );
149→  }
150→}
