  8→    const searchParams = request.nextUrl.searchParams;
  9→    const month = parseInt(searchParams.get("month") || String(new Date().getMonth() + 1), 10);
 10→    const year = parseInt(searchParams.get("year") || String(new Date().getFullYear()), 10);
 11→
 12→    const monthStart = new Date(year, month - 1, 1);
 13→    const monthEnd = new Date(year, month, 0);
 14→    const daysInMonth = monthEnd.getDate();
 15→
 16→    const transactions = await prisma.transaction.findMany({
 17→      where: {
 18→        userId,
 19→        deletedAt: null,
 20→        type: "EXPENSE",
 21→        date: {
 22→          gte: monthStart,
 23→          lte: monthEnd,
 24→        },
 25→      },
 26→      select: {
 27→        description: true,
 28→        amount: true,
 29→        date: true,
 30→      },
 31→      orderBy: {
 32→        date: "asc",
 33→      },
 34→    });
 35→
 36→    // Group transactions by day
 37→    const dayMap = new Map<number, { totalExpense: number; transactionCount: number; transactions: { description: string; amount: number }[] }>();
 38→
 39→    for (const t of transactions) {
 40→      const day = new Date(t.date).getDate();
 41→      const existing = dayMap.get(day) || { totalExpense: 0, transactionCount: 0, transactions: [] };
 42→      const absAmount = Math.abs(t.amount);
 43→      existing.totalExpense += absAmount;
 44→      existing.transactionCount += 1;
 45→      existing.transactions.push({ description: t.description, amount: absAmount });
 46→      dayMap.set(day, existing);
 47→    }
 48→
 49→    // Build days array for ALL days in the month
 50→    let maxExpense = 0;
 51→    const days = [];
 52→
 53→    for (let d = 1; d <= daysInMonth; d++) {
 54→      const dateObj = new Date(year, month - 1, d);
 55→      const dayData = dayMap.get(d);
 56→      const totalExpense = dayData?.totalExpense || 0;
 57→
 58→      if (totalExpense > maxExpense) {
 59→        maxExpense = totalExpense;
 60→      }
 61→
 62→      days.push({
 63→        date: dateObj.toISOString().split("T")[0],
 64→        dayOfMonth: d,
 65→        dayOfWeek: dateObj.getDay(),
 66→        totalExpense,
 67→        transactionCount: dayData?.transactionCount || 0,
 68→        transactions: dayData?.transactions || [],
 69→      });
 70→    }
 71→
 72→    // Compute summary
 73→    const daysWithExpenses = days.filter((d) => d.totalExpense > 0);
 74→    const totalExpenseSum = days.reduce((sum, d) => sum + d.totalExpense, 0);
 75→
 76→    let highestDay = { date: "", total: 0 };
 77→    let lowestDay = { date: "", total: Infinity };
 78→
 79→    for (const d of daysWithExpenses) {
 80→      if (d.totalExpense > highestDay.total) {
 81→        highestDay = { date: d.date, total: d.totalExpense };
 82→      }
 83→      if (d.totalExpense < lowestDay.total) {
 84→        lowestDay = { date: d.date, total: d.totalExpense };
 85→      }
 86→    }
 87→
 88→    if (daysWithExpenses.length === 0) {
 89→      lowestDay = { date: "", total: 0 };
 90→    }
 91→
 92→    const zeroDays = days.filter((d) => d.totalExpense === 0).length;
 93→    const averageDaily = daysInMonth > 0 ? totalExpenseSum / daysInMonth : 0;
 94→
 95→    return NextResponse.json({
 96→      days,
 97→      summary: {
 98→        highestDay,
 99→        lowestDay,
100→        averageDaily,
101→        zeroDays,
102→      },
103→      maxExpense,
104→    });
105→  } catch (error) {
106→    if (error instanceof Error && error.message === "Unauthorized") {
107→      return unauthorizedResponse();
108→    }
109→    console.error("Error fetching calendar data:", error);
110→    return NextResponse.json(
111→      { error: "Erro ao buscar dados do calendario" },
112→      { status: 500 }
113→    );
114→  }
