  1→import { NextRequest, NextResponse } from "next/server";
  2→import prisma from "@/lib/db";
  3→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  4→
  5→export async function GET(request: NextRequest) {
  6→  try {
  7→    const userId = await getAuthenticatedUserId();
  8→
  9→    const searchParams = request.nextUrl.searchParams;
 10→    const month = searchParams.get("month");
 11→    const year = searchParams.get("year");
 12→    const thresholdParam = searchParams.get("threshold");
 13→
 14→    const currentDate = new Date();
 15→    const targetMonth = month ? parseInt(month) : currentDate.getMonth() + 1;
 16→    const targetYear = year ? parseInt(year) : currentDate.getFullYear();
 17→    const threshold = thresholdParam ? parseFloat(thresholdParam) : 2; // Default: 2x average
 18→
 19→    // Get transactions for target month
 20→    const startDate = new Date(targetYear, targetMonth - 1, 1);
 21→    const endDate = new Date(targetYear, targetMonth, 0);
 22→
 23→    const currentMonthTransactions = await prisma.transaction.findMany({
 24→      where: {
 25→        userId,
 26→        date: {
 27→          gte: startDate,
 28→          lte: endDate,
 29→        },
 30→        type: "EXPENSE",
 31→        deletedAt: null,
 32→      },
 33→      include: {
 34→        category: true,
 35→      },
 36→    });
 37→
 38→    // Get transactions from last 6 months for average calculation
 39→    const sixMonthsAgo = new Date(targetYear, targetMonth - 7, 1);
 40→    const lastMonthEnd = new Date(targetYear, targetMonth - 1, 0);
 41→
 42→    const historicalTransactions = await prisma.transaction.findMany({
 43→      where: {
 44→        userId,
 45→        date: {
 46→          gte: sixMonthsAgo,
 47→          lte: lastMonthEnd,
 48→        },
 49→        type: "EXPENSE",
 50→        deletedAt: null,
 51→      },
 52→      include: {
 53→        category: true,
 54→      },
 55→    });
 56→
 57→    // Calculate average per category from historical data
 58→    // Track both total amount and which months had transactions
 59→    const categoryAverages: Record<string, {
 60→      total: number;
 61→      count: number;
 62→      months: Set<string>;
 63→      name: string;
 64→      color: string
 65→    }> = {};
 66→
 67→    for (const t of historicalTransactions) {
 68→      if (t.categoryId) {
 69→        if (!categoryAverages[t.categoryId]) {
 70→          categoryAverages[t.categoryId] = {
 71→            total: 0,
 72→            count: 0,
 73→            months: new Set(),
 74→            name: t.category?.name || "Sem categoria",
 75→            color: t.category?.color || "#888888",
 76→          };
 77→        }
 78→        categoryAverages[t.categoryId].total += Math.abs(t.amount);
 79→        categoryAverages[t.categoryId].count += 1;
 80→        // Track which month this transaction belongs to
 81→        const txDate = new Date(t.date);
 82→        const monthKey = `${txDate.getFullYear()}-${txDate.getMonth()}`;
 83→        categoryAverages[t.categoryId].months.add(monthKey);
 84→      }
 85→    }
 86→
 87→    // Calculate average transaction amount per category
 88→    const categoryAvgAmounts: Record<string, number> = {};
 89→    for (const [categoryId, data] of Object.entries(categoryAverages)) {
 90→      categoryAvgAmounts[categoryId] = data.count > 0 ? data.total / data.count : 0;
 91→    }
 92→
 93→    // Find unusual transactions (amount > threshold * category average)
 94→    // Only consider categories with history in at least 2 different months
 95→    const MIN_MONTHS_FOR_HISTORY = 2;
 96→
 97→    const unusualTransactions = currentMonthTransactions
 98→      .filter(t => {
 99→        if (!t.categoryId) return false;
100→        const categoryData = categoryAverages[t.categoryId];
101→        // Skip if category doesn't have enough historical data
102→        if (!categoryData || categoryData.months.size < MIN_MONTHS_FOR_HISTORY) return false;
103→        const avgAmount = categoryAvgAmounts[t.categoryId];
104→        if (!avgAmount || avgAmount === 0) return false;
105→        const amount = Math.abs(t.amount);
106→        return amount > threshold * avgAmount;
107→      })
108→      .map(t => {
109→        const avgAmount = categoryAvgAmounts[t.categoryId!] || 0;
110→        const amount = Math.abs(t.amount);
111→        const exceedsBy = avgAmount > 0 ? ((amount - avgAmount) / avgAmount) * 100 : 0;
112→
113→        return {
114→          id: t.id,
115→          description: t.description,
116→          amount: amount,
117→          date: t.date,
118→          categoryId: t.categoryId,
119→          categoryName: t.category?.name || null,
120→          categoryColor: t.category?.color || null,
121→          categoryAverage: avgAmount,
122→          exceedsBy,
123→        };
124→      })
125→      .sort((a, b) => b.exceedsBy - a.exceedsBy);
126→
127→    return NextResponse.json({
128→      transactions: unusualTransactions,
129→      threshold,
130→      period: {
131→        month: targetMonth,
132→        year: targetYear,
133→      },
134→    });
135→  } catch (error) {
136→    if (error instanceof Error && error.message === "Unauthorized") {
137→      return unauthorizedResponse();
138→    }
139→    console.error("Error fetching unusual transactions:", error);
140→    return NextResponse.json(
141→      { error: "Erro ao buscar transacoes incomuns" },
142→      { status: 500 }
143→    );
144→  }
145→}
