48→        transactionCount: data.transactionCount,
49→        averageExpense: data.transactionCount > 0 ? data.totalExpense / data.transactionCount : 0,
50→        percentage: totalExpense > 0 ? (data.totalExpense / totalExpense) * 100 : 0,
