52→      .sort((a, b) => b.totalExpense - a.totalExpense);
53→
54→    return NextResponse.json({
55→      origins,
56→      totalExpense,
57→    });
58→  } catch (error) {
59→    if (error instanceof Error && error.message === "Unauthorized") {
60→      return unauthorizedResponse();
61→    }
62→    console.error("Error fetching origins data:", error);
63→    return NextResponse.json(
64→      { error: "Erro ao buscar dados por origem" },
