  9→export async function GET(request: NextRequest) {
 10→  try {
 11→    const userId = await getAuthenticatedUserId();
 12→    const searchParams = request.nextUrl.searchParams;
 13→    const year = parseInt(
 14→      searchParams.get("year") || String(new Date().getFullYear()),
 15→      10
 16→    );
 17→
 18→    const yearStart = new Date(year, 0, 1);
 19→    const yearEnd = new Date(year, 11, 31, 23, 59, 59, 999);
 20→
 21→    // Query transactions, investment snapshots, and current investment totals in parallel
 22→    const [transactions, snapshots, investmentAggregate] = await Promise.all([
 23→      prisma.transaction.findMany({
 24→        where: {
 25→          userId,
 26→          deletedAt: null,
 27→          date: { gte: yearStart, lte: yearEnd },
 28→        },
 29→        select: { amount: true, type: true, date: true },
 30→      }),
 31→      prisma.investmentSnapshot.findMany({
 32→        where: {
 33→          userId,
 34→          year,
 35→        },
 36→        select: { month: true, totalValue: true },
 37→      }),
 38→      prisma.investment.aggregate({
 39→        where: { userId },
 40→        _sum: { currentValue: true, totalInvested: true },
 41→      }),
 42→    ]);
 43→
 44→    // Build a map of month -> snapshot totalValue
 45→    const snapshotMap = new Map<number, number>();
 46→    for (const snap of snapshots) {
 47→      snapshotMap.set(snap.month, snap.totalValue);
 48→    }
 49→
 50→    // Build monthly income/expense from transactions
 51→    const monthlyIncome = new Array<number>(12).fill(0);
 52→    const monthlyExpense = new Array<number>(12).fill(0);
 53→
 54→    for (const t of transactions) {
 55→      const d = new Date(t.date);
 56→      const monthIndex = d.getMonth(); // 0-based
 57→      if (t.type === "INCOME") {
 58→        monthlyIncome[monthIndex] += t.amount;
 59→      } else {
 60→        monthlyExpense[monthIndex] += Math.abs(t.amount);
 61→      }
 62→    }
 63→
 64→    const currentMonth = new Date().getMonth(); // 0-based
 65→    const isCurrentYear = year === new Date().getFullYear();
 66→    const currentInvestmentValue =
 67→      investmentAggregate._sum.currentValue || 0;
 68→
 69→    let cumulativeCash = 0;
 70→    const months = MONTH_LABELS.map((monthLabel, i) => {
 71→      const income = monthlyIncome[i];
 72→      const expense = monthlyExpense[i];
 73→      const cashDelta = income - expense;
 74→      cumulativeCash += cashDelta;
 75→
 76→      // For the current month of the current year, use live aggregate;
 77→      // otherwise use the snapshot (or 0)
 78→      const investmentValue =
 79→        isCurrentYear && i === currentMonth
 80→          ? currentInvestmentValue
 81→          : snapshotMap.get(i + 1) || 0;
 82→
 83→      const netWorth = cumulativeCash + investmentValue;
 84→
 85→      return {
 86→        monthLabel,
 87→        income,
 88→        expense,
 89→        cashDelta,
 90→        cumulativeCash,
 91→        investmentValue,
 92→        netWorth,
 93→      };
 94→    });
 95→
 96→    // Determine the "last relevant month" index for the current summary
 97→    const lastMonthIndex = isCurrentYear
 98→      ? currentMonth
 99→      : 11;
100→    const current = months[lastMonthIndex];
101→    const prevMonth = lastMonthIndex > 0 ? months[lastMonthIndex - 1] : null;
102→
103→    return NextResponse.json({
104→      months,
105→      current: {
106→        netWorth: current.netWorth,
107→        cashBalance: current.cumulativeCash,
108→        investmentValue: current.investmentValue,
109→        monthlyChange: prevMonth
110→          ? current.netWorth - prevMonth.netWorth
111→          : current.netWorth,
112→      },
113→    });
114→  } catch (error) {
115→    if (error instanceof Error && error.message === "Unauthorized") {
116→      return unauthorizedResponse();
117→    }
118→    console.error("Error fetching net worth data:", error);
119→    return NextResponse.json(
120→      { error: "Erro ao buscar dados de patrimonio" },
121→      { status: 500 }
122→    );
123→  }
