  1→import { NextResponse } from "next/server";
  2→import prisma from "@/lib/db";
  3→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  4→
  5→const MONTH_LABELS = [
  6→  "jan", "fev", "mar", "abr", "mai", "jun",
  7→  "jul", "ago", "set", "out", "nov", "dez",
  8→];
  9→
 10→export async function GET() {
 11→  try {
 12→    const userId = await getAuthenticatedUserId();
 13→    const now = new Date();
 14→
 15→    // 1. Average income from last 3 months (only months with income)
 16→    const threeMonthsAgo = new Date(now.getFullYear(), now.getMonth() - 3, 1);
 17→    const currentMonthEnd = new Date(now.getFullYear(), now.getMonth() + 1, 0);
 18→
 19→    const incomeTransactions = await prisma.transaction.findMany({
 20→      where: {
 21→        userId,
 22→        type: "INCOME",
 23→        date: { gte: threeMonthsAgo, lte: currentMonthEnd },
 24→        deletedAt: null,
 25→      },
 26→    });
 27→
 28→    const incomeByMonth = new Map<string, number>();
 29→    for (const t of incomeTransactions) {
 30→      const d = new Date(t.date);
 31→      const key = `${d.getFullYear()}-${d.getMonth()}`;
 32→      incomeByMonth.set(key, (incomeByMonth.get(key) || 0) + Math.abs(t.amount));
 33→    }
 34→    const monthlyIncomes = Array.from(incomeByMonth.values());
 35→    const averageIncome =
 36→      monthlyIncomes.length > 0
 37→        ? monthlyIncomes.reduce((sum, v) => sum + v, 0) / monthlyIncomes.length
 38→        : 0;
 39→
 40→    // 2. Active recurring expenses with effective amounts
 41→    const activeRecurring = await prisma.recurringExpense.findMany({
 42→      where: { userId, isActive: true },
 43→    });
 44→
 45→    const recurringWithLatestAmount = await Promise.all(
 46→      activeRecurring.map(async (recurring) => {
 47→        const latestTransaction = await prisma.transaction.findFirst({
 48→          where: { userId, recurringExpenseId: recurring.id },
 49→          orderBy: { date: "desc" },
 50→          select: { amount: true },
 51→        });
 52→        return {
 53→          ...recurring,
 54→          effectiveAmount: latestTransaction?.amount ?? recurring.defaultAmount,
 55→        };
 56→      })
 57→    );
 58→
 59→    // 3. Future installments (next 12 months) - grouped
 60→    const startOfCurrentMonth = new Date(now.getFullYear(), now.getMonth(), 1);
 61→    const endDate = new Date(now.getFullYear(), now.getMonth() + 12, 0);
 62→
 63→    const futureInstallments = await prisma.transaction.findMany({
 64→      where: {
 65→        userId,
 66→        isInstallment: true,
 67→        installmentId: { not: null },
 68→        date: { gte: startOfCurrentMonth, lte: endDate },
 69→        deletedAt: null,
 70→      },
 71→    });
 72→
 73→    // 3b. Standalone installments (manually tagged, no group) - project remaining
 74→    const standaloneInstallments = await prisma.transaction.findMany({
 75→      where: {
 76→        userId,
 77→        isInstallment: true,
 78→        installmentId: null,
 79→        totalInstallments: { not: null },
 80→        currentInstallment: { not: null },
 81→        deletedAt: null,
 82→      },
 83→    });
 84→
 85→    const projectedStandalone: Array<{ amount: number; date: Date }> = [];
 86→    standaloneInstallments.forEach((t) => {
 87→      if (!t.currentInstallment || !t.totalInstallments) return;
 88→      const remaining = t.totalInstallments - t.currentInstallment;
 89→      const tDate = new Date(t.date);
 90→      for (let j = 1; j <= remaining; j++) {
 91→        const futureDate = new Date(tDate);
 92→        futureDate.setMonth(tDate.getMonth() + j);
 93→        if (futureDate >= startOfCurrentMonth && futureDate <= endDate) {
 94→          projectedStandalone.push({ amount: Math.abs(t.amount), date: futureDate });
 95→        }
 96→      }
 97→    });
 98→
 99→    // 4. Build 12-month baseline
100→    const months = [];
101→    for (let i = 0; i < 12; i++) {
102→      const projMonth = now.getMonth() + i;
103→      const projYear = now.getFullYear() + Math.floor(projMonth / 12);
104→      const normalizedMonth = (projMonth % 12) + 1;
105→      const label = `${MONTH_LABELS[normalizedMonth - 1]}/${String(projYear).slice(-2)}`;
106→
107→      const monthInstallments = futureInstallments.filter((t) => {
108→        const d = new Date(t.date);
109→        return d.getMonth() + 1 === normalizedMonth && d.getFullYear() === projYear;
110→      });
111→      const monthStandalone = projectedStandalone.filter((t) => {
112→        return t.date.getMonth() + 1 === normalizedMonth && t.date.getFullYear() === projYear;
113→      });
114→      const installmentsTotal =
115→        monthInstallments.reduce((sum, t) => sum + Math.abs(t.amount), 0) +
116→        monthStandalone.reduce((sum, t) => sum + t.amount, 0);
117→
118→      const recurringExpensesTotal = recurringWithLatestAmount
119→        .filter((r) => r.type === "EXPENSE")
120→        .reduce((sum, r) => sum + Math.abs(r.effectiveAmount), 0);
121→
122→      months.push({
123→        month: normalizedMonth,
124→        year: projYear,
125→        label,
126→        currentExpenses: recurringExpensesTotal + installmentsTotal,
127→        recurringExpenses: recurringExpensesTotal,
128→        installmentsTotal,
129→      });
130→    }
131→
132→    return NextResponse.json({ averageIncome, months });
133→  } catch (error) {
134→    if (error instanceof Error && error.message === "Unauthorized") {
135→      return unauthorizedResponse();
136→    }
137→    console.error("Error fetching simulation data:", error);
138→    return NextResponse.json(
139→      { error: "Erro ao buscar dados de simulação" },
140→      { status: 500 }
141→    );
142→  }
143→}
