 61→    const userId = await getAuthenticatedUserId();
 62→
 63→    const searchParams = request.nextUrl.searchParams;
 64→    const closingDay = parseInt(searchParams.get("closingDay") || "13");
 65→    const origin = searchParams.get("origin"); // Optional: filter by card/origin
 66→
 67→    // Get bill periods (last 6 months)
 68→    const periods = getBillPeriods(closingDay, 6);
 69→
 70→    // Fetch transactions for each period
 71→    const bills = await Promise.all(
 72→      periods.map(async (period) => {
 73→        const where: Record<string, unknown> = {
 74→          userId,
 75→          date: {
 76→            gte: period.startDate,
 77→            lte: period.endDate,
 78→          },
 79→          deletedAt: null,
 80→          type: "EXPENSE", // Only expenses for bills
 81→        };
 82→
 83→        if (origin) {
 84→          where.origin = origin;
 85→        }
 86→
 87→        const transactions = await prisma.transaction.findMany({
 88→          where,
 89→          include: {
 90→            category: true,
 91→          },
 92→          orderBy: {
 93→            date: "desc",
 94→          },
 95→        });
 96→
 97→        // Calculate transaction total (only period transactions)
 98→        const transactionTotal = transactions.reduce(
 99→          (sum, t) => sum + Math.abs(t.amount),
100→          0
101→        );
102→
103→        // Look for carryover from previous month's bill payment
104→        // Calculate previous month (handle January -> December of previous year)
105→        const prevMonth = period.month === 1 ? 12 : period.month - 1;
106→        const prevYear = period.month === 1 ? period.year - 1 : period.year;
107→
108→        // Query for partial bill payments from the previous month
109→        const carryoverQuery: Record<string, unknown> = {
110→          userId,
111→          billMonth: prevMonth,
112→          billYear: prevYear,
113→          paymentType: "PARTIAL",
114→          amountCarried: { gt: 0 },
115→        };
116→
117→        if (origin) {
118→          carryoverQuery.origin = origin;
119→        }
120→
121→        const carryoverPayment = await prisma.billPayment.findFirst({
122→          where: carryoverQuery,
123→        });
124→
125→        // Build carryover info if found
126→        let carryover: CarryoverInfo | null = null;
127→        let carryoverAmount = 0;
128→        let interestAmount = 0;
129→
130→        if (carryoverPayment) {
131→          carryoverAmount = carryoverPayment.amountCarried;
132→          interestAmount = carryoverPayment.interestAmount || 0;
133→
134→          const monthNames = [
135→            "Janeiro", "Fevereiro", "Marco", "Abril", "Maio", "Junho",
136→            "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"
137→          ];
138→
139→          carryover = {
140→            amount: carryoverAmount,
141→            interest: interestAmount,
142→            fromBill: `${monthNames[prevMonth - 1]}/${prevYear}`,
143→            billPaymentId: carryoverPayment.id,
144→          };
145→        }
146→
147→        // Total includes transaction total + carryover + interest
148→        const total = transactionTotal + carryoverAmount + interestAmount;
149→
150→        // Group by category
151→        const categoryTotals: Record<
152→          string,
153→          { name: string; color: string; total: number; count: number }
154→        > = {};
155→
156→        for (const t of transactions) {
157→          const catId = t.categoryId || "uncategorized";
158→          const catName = t.category?.name || "Sem categoria";
159→          const catColor = t.category?.color || "#9CA3AF";
160→
161→          if (!categoryTotals[catId]) {
162→            categoryTotals[catId] = {
163→              name: catName,
164→              color: catColor,
165→              total: 0,
166→              count: 0,
167→            };
168→          }
169→          categoryTotals[catId].total += Math.abs(t.amount);
170→          categoryTotals[catId].count++;
171→        }
172→
173→        const categories = Object.entries(categoryTotals)
174→          .map(([id, data]) => ({
175→            id,
176→            ...data,
177→            percentage: total > 0 ? (data.total / total) * 100 : 0,
178→          }))
179→          .sort((a, b) => b.total - a.total);
180→
181→        return {
182→          label: period.label,
183→          month: period.month,
184→          year: period.year,
185→          startDate: period.startDate.toISOString(),
186→          endDate: period.endDate.toISOString(),
187→          dueDate: period.dueDate.toISOString(),
188→          total,
189→          transactionTotal,
190→          carryover,
191→          transactionCount: transactions.length,
192→          categories,
193→          transactions: transactions.map((t) => ({
194→            id: t.id,
195→            description: t.description,
196→            amount: t.amount,
197→            date: t.date.toISOString(),
198→            origin: t.origin,
199→            categoryId: t.categoryId,
200→            categoryName: t.category?.name || "Sem categoria",
201→            categoryColor: t.category?.color || "#9CA3AF",
202→            isInstallment: t.isInstallment,
203→            currentInstallment: t.currentInstallment,
204→          })),
205→        };
206→      })
207→    );
208→
209→    // Get available origins for filtering
210→    const origins = await prisma.origin.findMany({
211→      where: { userId },
212→      orderBy: { name: "asc" },
213→    });
214→
215→    // Calculate comparison with previous bill
216→    const billsWithComparison = bills.map((bill, index) => {
217→      const previousBill = bills[index + 1];
218→      const changePercentage = previousBill
219→        ? ((bill.total - previousBill.total) / previousBill.total) * 100
220→        : null;
221→
222→      return {
223→        ...bill,
224→        previousTotal: previousBill?.total || null,
225→        changePercentage,
226→      };
227→    });
228→
229→    return NextResponse.json({
230→      closingDay,
231→      bills: billsWithComparison,
232→      origins,
233→    });
234→  } catch (error) {
235→    if (error instanceof Error && error.message === "Unauthorized") {
236→      return unauthorizedResponse();
237→    }
238→    console.error("Error fetching bills:", error);
239→    return NextResponse.json(
240→      { error: "Erro ao buscar faturas" },
241→      { status: 500 }
242→    );
243→  }
244→}
245→

